# truevision_v2.py
# Public-facing TrueVision API that maintains client-side continuity/sessions,
# supports live video, optional audio, and proxies to your private Crystal Engine.
# Includes a Presenter with Observer/Narrator/Assistant modes.

from __future__ import annotations
from dataclasses import dataclass
from typing import Any, Dict, List, Optional, Union, Callable
import time
import uuid
import threading

# ==== Optional local engine wiring (for YOUR builds/tests only) ====
try:
    from crystal_engine_v3 import Memory, Crystal  # your engine core
