# ===================== Engine client abstraction =====================
class EngineClient:
    def ingest(self, payload: Dict[str, Any]) -> Dict[str, Any]:
        raise NotImplementedError
    def ingest_audio(self, payload: Dict[str, Any]) -> Dict[str, Any]:
