# -------- Presenter (formats human-level outputs) --------
class Presenter:
    def __init__(self, mode: str = "observer", verbosity: str = "simple"):
        self.mode = mode  # observer | narrator | assistant | silent
        self.verbosity = verbosity  # simple | verbose

    def set_mode(self, mode: str):
        self.mode = mode

    def set_verbosity(self, verbosity: str):
        self.verbosity = verbosity

    def callout(self, desc_text: str, bind: Optional[Dict[str, Any]]) -> str:
        if self.mode == "silent":
            return ""
        # Base line from descriptor (e.g., "red scene, motion=0.23")
        base = ""
        if self.mode in ("observer", "assistant"):
            base = f"{desc_text.split(',')[0]}" if desc_text else ""
        elif self.mode == "narrator":
            base = desc_text

        bind_line = ""
        if bind and bind.get("binding"):
            b = bind["binding"]
            if b.get("unified"):
                bind_line = b["unified"]
            else:
                strength = b.get("strength")
                mems = b.get("members") or []
                bind_line = f"Binding {strength:.2f} · {len(mems)} items linked" if strength is not None else f"{len(mems)} items linked"

        # Compose
        if base and bind_line:
            text = f"{base} — {bind_line}"
        else:
            text = base or bind_line

        if self.mode == "assistant" and text:
            text += " · Say 'focus' or 'alert' to act"
        return text

    def summary(self, events: List[Dict[str, Any]], window_s: float = 10.0) -> str:
        if not events:
            return "No recent activity."
        now = time.time()
        recent = [e for e in events if (now - float(e.get("t1", now))) <= window_s]
        persons = len([e for e in recent if "person" in (e.get("what") or "")])
        moves = len([e for e in recent if "ingested" in e.get("action","")])
        return f"Past {int(window_s)}s: {persons} person-like events; {moves} observations."

# -------- Local engine client (for YOUR internal use) --------
class LocalCrystalEngineClient(EngineClient):
    """
    Wires TrueVision to YOUR engine locally:
      - AdvancedSemanticAnalyzer -> semantic features/pressure
      - Memory/Crystal           -> store & evolve concepts
      - CrystalBindingController -> working-memory binding
      - CognitiveDimensionalLayer-> typed foresight insights
    """
    def __init__(self):
        if not _LOCAL_ENGINE_AVAILABLE:
            raise RuntimeError("Local engine modules not available in this build.")
        self.memory = Memory()
        self.semantic = AdvancedSemanticAnalyzer(self.memory)
        self.binding = CrystalBindingController(self.memory)
        self._events: List[Dict[str, Any]] = []  # simple narrative buffer

    # ---- Engine API surface ----
    def ingest(self, payload: Dict[str, Any]) -> Dict[str, Any]:
        text = payload.get("text", "") or payload.get("context", "")
        context = payload.get("context", "")
        continuity_id = payload.get("continuity_id")
        session_id = payload.get("session_id")
        feats = self.semantic.analyze_text(text, context=context)
        concept_key = payload.get("concept_key") or (text[:40] or "observation").strip()
        crystal: Crystal = self.memory.get_or_create_crystal(concept_key)
        try:
            crystal.set_facet("definition", text)
            # attractions per your new schema
            if hasattr(crystal, "bump_attraction"):
                crystal.bump_attraction("conceptual_depth", getattr(feats, "semantic_density", 0.0))
                val = max(0.0, getattr(feats, "emotional_valence", 0.0))
                crystal.bump_attraction("emotional_resonance", val)
                crystal.bump_attraction("temporal_significance", 0.1)
            if hasattr(crystal, "touch"):
                crystal.touch()
        except Exception:
            pass
        self._events.append({
            "t0": payload.get("t0", time.time()),
            "t1": time.time(),
            "who": None,
            "action": "ingested",
            "what": concept_key,
            "where": None,
            "confidence": 0.55,
            "meta": {"context": context, "continuity_id": continuity_id, "session_id": session_id, "channel": "video"},
        })
        return {"ok": True, "concept": concept_key, "crystal_id": getattr(crystal, "id", None)}

    def ingest_audio(self, payload: Dict[str, Any]) -> Dict[str, Any]:
        text = payload.get("text", "")
        context = payload.get("context", "")
        speaker = payload.get("speaker_id") or "speaker"
        concept_key = payload.get("concept_key") or f"voice {speaker}"
        continuity_id = payload.get("continuity_id")
        session_id = payload.get("session_id")
        depth = 0.0; val = 0.0
        if text:
            try:
                feats = self.semantic.analyze_text(text, context=context)
                depth = getattr(feats, "semantic_density", 0.0)
                val = max(0.0, getattr(feats, "emotional_valence", 0.0))
            except Exception:
                pass
        crystal: Crystal = self.memory.get_or_create_crystal(concept_key)
        try:
            if text and hasattr(crystal, "set_facet"):
                crystal.set_facet("utterance", text)
            if hasattr(crystal, "bump_attraction"):
                energy = float((payload.get("prosody") or {}).get("energy", 0.0))
                crystal.bump_attraction("emotional_resonance", max(val, min(1.0, energy)))
                crystal.bump_attraction("temporal_significance", 0.3)
                crystal.bump_attraction("conceptual_depth", depth)
            if hasattr(crystal, "touch"):
                crystal.touch()
        except Exception:
            pass
        self._events.append({
            "t0": payload.get("t0", time.time()),
            "t1": time.time(),
            "who": speaker,
            "action": "ingested_audio",
            "what": concept_key,
            "where": None,
            "confidence": 0.6,
            "meta": {"context": context, "continuity_id": continuity_id, "session_id": session_id, "channel": "audio", "prosody": payload.get("prosody"), "emotion": payload.get("emotion")},
        })
        return {"ok": True, "concept": concept_key, "crystal_id": getattr(crystal, "id", None)}

    def bind(self, context: str = "") -> Dict[str, Any]:
        b = self.binding.attempt_crystal_binding(trigger_context=context)
        if not b:
            return {"binding": None}
        return {
            "binding": {
                "id": b.id,
                "members": b.bound_crystal_ids,
                "dominant": b.dominant_crystal,
                "strength": b.binding_strength,
                "activation": b.activation_level,
                "unified": b.unified_content,
                "emergent": b.emergent_properties,
            }
        }

    def narrative(self) -> Dict[str, Any]:
        return {"events": list(self._events)}

    def foresight(self, concept: str, perspective: Optional[str] = None) -> Dict[str, Any]:
        layer = CognitiveDimensionalLayer(id=f"tv_{concept}", base_content=concept, source_facet="definition", layer_index=0)
        p = (perspective or "temporal").lower()
        mapping = {
            "temporal": ForesightType.TEMPORAL_PROJECTION,
            "causal": ForesightType.CAUSAL_EXTRAPOLATION,
            "pattern": ForesightType.PATTERN_COMPLETION,
            "analogical": ForesightType.ANALOGICAL_BRIDGING,
            "emergent": ForesightType.EMERGENT_PROPERTIES,
            "constraint": ForesightType.CONSTRAINT_ANALYSIS,
        }
        ftype = mapping.get(p, ForesightType.TEMPORAL_PROJECTION)
        insight = layer.generate_foresight_insight(ftype)
        return {"insight": {"text": insight.insight_text, "type": insight.foresight_type.value, "confidence": insight.confidence, "horizon": insight.temporal_horizon, "novel": insight.novel_connections}}

# -------- Remote engine client (for selling TrueVision as an SDK) --------
class RemoteCrystalEngineClient(EngineClient):
    def __init__(self, base_url: str, api_key: str, request_fn: Optional[Callable] = None):
