from __future__ import annotations

import os
import re
import json
import time
import threading
import queue
from datetime import datetime
from typing import Dict, List, Optional, Callable

# --- Core engine & bot (single surface) ---
from crystal_engine_v3 import Memory, migrate_facets, CognitiveMode  # modes from core
from chatbot_core_v3 import FractalCrystalBot
# Optional: harvester can be wired in as a feeder (kept separate)
