# --------------------------- Utilities ---------------------------

def now_iso() -> str:
    return datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")

def default_mem_path() -> str:
    env = os.environ.get("CRYSTAL_MEM_PATH")
    if env:
        return env
    return os.path.join(os.path.dirname(__file__), "memory_fractal.json")


# ---------------------- Mode Manager (unchanged behavior) ----------------------

class CognitiveModeManager:
    """
    Governs when to transition between LIVE_USER, ACTIVE_LEARNING, and SOLITARY_STUDY.
    Uses single CognitiveMode enum from crystal_engine_v3.
    """
    def __init__(self):
        self.current_mode = CognitiveMode.LIVE_USER
        self.mode_start_time = time.time()
        self.user_idle_threshold = 300      # 5 minutes idle -> eligible for SOLITARY_STUDY
        self.study_session_duration = 600   # 10 minutes study before re-evaluation
        self.last_user_interaction = time.time()

    def should_transition_to_study(self) -> bool:
        idle_time = time.time() - self.last_user_interaction
        return (self.current_mode == CognitiveMode.LIVE_USER and idle_time > self.user_idle_threshold)

    def should_exit_study(self) -> bool:
        study_time = time.time() - self.mode_start_time
        return (self.current_mode == CognitiveMode.SOLITARY_STUDY and study_time > self.study_session_duration)

    def transition_to(self, mode: CognitiveMode):
        if mode != self.current_mode:
            old = self.current_mode
            self.current_mode = mode
            self.mode_start_time = time.time()
            return old, mode
        return None, None

    def user_interaction_detected(self):
        self.last_user_interaction = time.time()
        if self.current_mode != CognitiveMode.LIVE_USER:
            return self.transition_to(CognitiveMode.LIVE_USER)
        return None, None


# ---------------------- Subconscious (merged) ----------------------

class EnhancedSubconsciousMind(threading.Thread):
    """
    Background cognition (merged):
    - From integrated mind: tracks weak concepts, missing facets, practice queues, attention guidance.
    - From dual process mind: L2 abstract checks, L4 foresight checks, probe generation & coherence evaluation.

    Communicates with the Conscious via queues and direct calls.
    """

    DAEMON_INTERVAL = 1.0  # seconds
    MAX_LOG_LINES   = 20000

    def __init__(self, memory: Memory, mode_manager: CognitiveModeManager, log_path: str, ask_callable: Callable[[str], str]):
        super().__init__(daemon=True)
        self.memory = memory
        self.mode_manager = mode_manager
        self.log_path = log_path
        self._stop = threading.Event()

        # Bridge to conscious (use bot.chat provided by EnhancedConsciousMind)
        self.ask_callable = ask_callable

        # Queues & observations
        self.attention_queue = queue.Queue()  # HIGH/MEDIUM attention pointers
        self.practice_queue = queue.Queue()   # study questions for SOLITARY_STUDY
        self.observations: List[dict] = []    # passive observations during live mode

        # Weakness tracking
        self.weak_concepts: set[str] = set()
        self.missing_facets: Dict[str, List[str]] = {}  # concept -> missing facet names
        self.poor_connections: set[str] = set()

        # logging
        self._log_lock = threading.Lock()
        self._line_count = 0

    # ---------------- logging ----------------
    def _log(self, kind: str, payload: dict):
        rec = {"t": now_iso(), "kind": kind, **payload}
        line = json.dumps(rec, ensure_ascii=False)
        try:
            with self._log_lock:
                with open(self.log_path, "a", encoding="utf-8") as f:
                    f.write(line + "\n")
                self._line_count += 1
                if self._line_count >= self.MAX_LOG_LINES:
                    self._rotate()
        except Exception:
            pass

    def _rotate(self):
        try:
            base, ext = os.path.splitext(self.log_path)
            rotated = f"{base}.{int(time.time())}.log"
            os.replace(self.log_path, rotated)
            self._line_count = 0
            self._log("rotate", {"to": rotated})
        except Exception:
            pass

    # ---------------- thread core ----------------
    def run(self):
        self._log("start", {"msg": "subconscious online"})
        try:
            while not self._stop.is_set():
                mode = self.mode_manager.current_mode
                if mode == CognitiveMode.LIVE_USER:
                    self._live_user_processing()
                elif mode == CognitiveMode.ACTIVE_LEARNING:
                    self._active_learning_processing()
                elif mode == CognitiveMode.SOLITARY_STUDY:
                    self._solitary_study_processing()

                # Probing cycle (merged from dual process)
                self._probe_cycle()

                time.sleep(self.DAEMON_INTERVAL)
        except Exception as e:
            self._log("error", {"msg": str(e)})
        finally:
            self._log("stop", {"msg": "subconscious offline"})

    def stop(self):
        self._stop.set()

    # ---------------- integrated behavior ----------------
    def _get_recently_accessed_crystals(self, limit: int = 10):
        items = list(self.memory.crystals.values())
        items.sort(key=lambda c: c.last_accessed, reverse=True)
        return items[:limit]

    def _identify_missing_facets(self, c) -> List[str]:
        missing = []
        L = int(getattr(c, "evolution_level", 1))
        # L2 expectations
        if L >= 2:
            for facet in ("example", "operation", "abstract"):
                try:
                    if not c.get_facet(facet):
                        missing.append(facet)
                except Exception:
                    pass
        # L3 expectations
        if L >= 3:
            for facet in ("cause", "effect", "temporal", "spatial"):
                try:
                    if not c.get_facet(facet):
                        missing.append(facet)
                except Exception:
                    pass
        return missing

    def _assess_concept_priority(self, c) -> str:
        # High: used often and missing multiple key facets
        if c.usage_count > 5 and len(self._identify_missing_facets(c)) > 2:
            return "HIGH"
        # High: central but undefined
        if len(c.connections) > 8:
            try:
                if not c.get_facet("definition"):
                    return "HIGH"
            except Exception:
                pass
        # Medium: some use & some gaps
        if c.usage_count > 2 and self._identify_missing_facets(c):
            return "MEDIUM"
        return "LOW"

    def _suggest_focus_areas(self, c) -> List[str]:
        out = []
        missing = self._identify_missing_facets(c)
        if "definition" in missing:
            out.append("needs clear definition")
        if "example" in missing:
            out.append("needs concrete examples")
        if "cause" in missing:
            out.append("needs causal relationships")
        if len(c.connections) < 3:
