    def _active_learning_processing(self):
        recent = self._get_recently_accessed_crystals(limit=5)
        for c in recent:
            pri = self._assess_concept_priority(c)
            if pri in ("HIGH", "MEDIUM"):
                self.attention_queue.put({
                    "concept": c.concept,
                    "priority": pri,
                    "reason": "Critical gap" if pri == "HIGH" else "Strengthen knowledge",
                    "suggested_focus": self._suggest_focus_areas(c)
                })
        self._log("learning_guidance", {
            "evaluated": len(recent),
            "flagged": sum(1 for c in recent if self._assess_concept_priority(c) == "HIGH")
        })

    def _solitary_study_processing(self):
        # Generate practice questions from weaknesses
        q = self._generate_practice_questions()
        for item in q:
