    def _check_L4_foresight(self, c):
        # For L4 concepts, ensure I_* and O_* foresight facets are present
        try:
            L = int(getattr(c, "evolution_level", 1))
        except Exception:
            L = 1
        if L >= 4:
            need = []
            for fac in ("I_coherence", "I_bridge", "O_plan"):
