                # scan for concept id
                target_cid = None
                for cid, cc in self.memory.crystals.items():
                    if cc.concept.lower() == t:
                        target_cid = cid
                        break
                if target_cid:
                    c = self.memory.get(target_cid)
                    c.usage_count = getattr(c, "usage_count", 0) + 1
                    break
        else:
            self._log("eval_ok", {"q": qtext, "a": answer})

    def _probe_cycle(self):
        # Scan & check (L2/L4)
        hot = self._hot_crystals(limit=30)
        for c in hot:
            self._check_L2_abstract(c)
            self._check_L4_foresight(c)

        # Generate probes and evaluate answers using the conscious ask_callable
        probes = self._make_probes(hot, limit=4)
        for p in probes:
            try:
                a = self.ask_callable(p)
                self._evaluate_coherence(p, a)
            except Exception as e:
                self._log("probe_error", {"q": p, "err": str(e)})


