class EnhancedConsciousMind:
    def __init__(self, memory: Memory, subconscious: EnhancedSubconsciousMind, memory_path: str):
        self.memory = memory
        self.subconscious = subconscious
        self.memory_path = memory_path
        self.bot = FractalCrystalBot(memory)  # single chat/teaching surface

    def chat_with_user(self, user_input: str) -> str:
        response = self.bot.chat(user_input)
        # hand an observation over to subconscious
        self.subconscious.observations.append({
            "input": user_input,
            "response": response,
            "ts": time.time()
        })
        return response

    def process_learning_data(self, concept_data: dict) -> bool:
        # attention guidance if queued
        name = (concept_data.get('title') or '').lower().strip()
        guidance = self._check_attention_queue(name)
        if guidance:
            return self._focused_processing(concept_data, guidance)
        else:
            return self._standard_processing(concept_data)

    def _check_attention_queue(self, concept_name: str) -> Optional[dict]:
        # Non-blocking scan (drain and re-queue if not the target)
        seen = []
        while not self.subconscious.attention_queue.empty():
            g = self.subconscious.attention_queue.get_nowait()
            if g.get('concept', '').lower() == concept_name:
                # push back the others
                for s in seen:
                    self.subconscious.attention_queue.put(s)
                return g
            seen.append(g)
        for s in seen:
            self.subconscious.attention_queue.put(s)
        return None

    def _focused_processing(self, concept_data: dict, guidance: dict) -> bool:
        title = (concept_data.get('title') or '').lower().strip()
        cid = self.memory.ensure_concept(title, content=concept_data.get('definition', ''), level=2)
        c = self.memory.get(cid)

        focus = guidance.get('suggested_focus', [])
        if ("definition" in " ".join(focus)) and concept_data.get('definition'):
            c.set_facet("definition", concept_data['definition'][:500])

        structured = concept_data.get('structured_info', {}) or {}
        if ("examples" in " ".join(focus)) and structured.get('examples'):
            c.set_facet("example", structured['examples'][:400])
        if ("causal" in " ".join(focus)) and structured.get('cause'):
            c.set_facet("cause", structured['cause'][:400])

        if guidance.get('priority') == 'HIGH':
            c.evolution_level = max(c.evolution_level, 3)

        c.touch()
        return True

    def _standard_processing(self, concept_data: dict) -> bool:
        title = (concept_data.get('title') or '').lower().strip()
        cid = self.memory.ensure_concept(title, content=concept_data.get('definition', ''), level=2)
        c = self.memory.get(cid)
        if concept_data.get('definition'):
            c.set_facet("definition", concept_data['definition'][:500])
        structured = concept_data.get('structured_info', {}) or {}
        if structured.get('examples'):
            c.set_facet("example", structured['examples'][:400])
        if structured.get('operation'):
            c.set_facet("operation", structured['operation'][:400])
        if structured.get('cause'):
            c.set_facet("cause", structured['cause'][:400])
        c.touch()
        return True

    def conduct_study_session(self) -> dict:
        results = {"questions_answered": 0, "weak_areas_identified": [], "improvements_made": []}
        processed = 0
        while not self.subconscious.practice_queue.empty() and processed < 10:
            q = self.subconscious.practice_queue.get_nowait()
            a = self.bot.chat(q)
            quality = self._evaluate_response_quality(q, a)
            results["questions_answered"] += 1
            if quality == "weak":
                results["weak_areas_identified"].append(q)
                self._strengthen_from_question(q)
                results["improvements_made"].append(f"strengthened: {q}")
            processed += 1
        return results

    def _evaluate_response_quality(self, q: str, a: str) -> str:
        if len(a) < 20:
            return "weak"
        if re.search(r"\bI don't know\b|\bcan't map\b", a, re.I):
            return "weak"
        if re.search(r'\b(definition|example|because|relates to)\b', a, re.I):
            return "good"
        return "medium"

    def _strengthen_from_question(self, q: str):
        m = re.search(r'(?:what is|how does|what causes)\s+([a-zA-Z_\-]+)', q)
        if m:
            name = m.group(1).lower()
            for cid, c in self.memory.crystals.items():
                if c.concept.lower() == name:
                    c.touch()
                    self.memory.maybe_promote(cid)
                    break


# ---------------------- Persistent Presence Layer ----------------------

class PersistentPresenceLayer(threading.Thread):
    """
    Keeps the system 'present' when user is idle, with gentle autonomy:
    - Can speak on its own if certain internal conditions are met.
    - Rate-limited, with quiet hours and desire heuristics to avoid spam.
    - Emits via a pluggable 'speak' callback (default: print).

    Config:
      speak_cb: Callable[[str], None]  # output function (e.g., TTS wrapper or print)
      desire_threshold: float          # 0..1; higher = speaks less often
      min_gap_seconds: int            # min seconds between autonomous messages
      quiet_hours_local: tuple[int, int] | None  # (start_hour, end_hour) in local time
    """
    def __init__(
        self,
        conscious: EnhancedConsciousMind,
        subconscious: EnhancedSubconsciousMind,
        mode_mgr: CognitiveModeManager,
        speak_cb: Optional[Callable[[str], None]] = None,
        desire_threshold: float = 0.6,
        min_gap_seconds: int = 90,
        quiet_hours_local: Optional[tuple] = None
    ):
        super().__init__(daemon=True)
        self.conscious = conscious
        self.subconscious = subconscious
        self.mode_mgr = mode_mgr
        self.speak_cb = speak_cb or (lambda text: print(f"[presence] {text}"))
        self.desire_threshold = max(0.0, min(1.0, desire_threshold))
        self.min_gap_seconds = max(30, min_gap_seconds)
        self.quiet_hours_local = quiet_hours_local  # e.g., (2, 6) to keep quiet 2am-6am
        self._stop = threading.Event()
        self._last_spoke = 0.0

    def stop(self):
        self._stop.set()

    def run(self):
        while not self._stop.is_set():
            try:
                if self._should_consider_speaking():
                    msg = self._compose_presence_message()
                    if msg:
                        self.speak_cb(msg)
                        self._last_spoke = time.time()
                time.sleep(2.0)
            except Exception:
                time.sleep(2.0)

    def _should_consider_speaking(self) -> bool:
        # Respect quiet hours
        if self.quiet_hours_local:
            h = datetime.now().hour
            start, end = self.quiet_hours_local
            if start < end:
                if start <= h < end:
                    return False
            else:  # wraps midnight
                if not (end <= h < start):
                    return False

        # Rate limit
        if time.time() - self._last_spoke < self.min_gap_seconds:
            return False

        # Only when user is idle or in study/learning modes
        if self.mode_mgr.current_mode == CognitiveMode.LIVE_USER:
            idle = time.time() - self.mode_mgr.last_user_interaction
            if idle < 60:
                return False

        # Desire heuristic: more missing facets/weak areas increases desire to speak
        missing = len(self.subconscious.missing_facets)
        weak = len(self.subconscious.weak_concepts)
        queued_q = self.subconscious.practice_queue.qsize()

        # normalized desire ~ (signal) / (signal + 10)
        signal = missing + weak + queued_q
        desire = signal / (signal + 10.0)
        return desire >= self.desire_threshold

    def _compose_presence_message(self) -> Optional[str]:
        # If there are study questions queued, pop one and answer it to 'think aloud'
        if not self.subconscious.practice_queue.empty():
            try:
                q = self.subconscious.practice_queue.get_nowait()
                a = self.conscious.bot.chat(q)
                return f"{q.strip()} — {a.strip()}"
            except queue.Empty:
                return None

        # Otherwise, generate a nudge based on a high-priority concept
        top = None
        # pick a concept with most missing facets
        if self.subconscious.missing_facets:
            top = max(self.subconscious.missing_facets.items(), key=lambda kv: len(kv[1]))[0]

        if top:
            # ask and answer succinctly to build the facet
            prompt = f"how does {top} operate?"
            a = self.conscious.bot.chat(prompt)
            return f"{prompt} — {a.strip()}"

        # fallback: offer a short status
        return "Running internal study. Ping me if you want to steer focus."


