        # subconscious (needs a callable to ask the conscious/bot)
        self.subconscious = EnhancedSubconsciousMind(
            memory=self.mem,
            mode_manager=self.mode_mgr,
            log_path=self.log_path,
            ask_callable=lambda q: self.conscious.bot.chat(q)  # deferred (conscious set below)
        )

        # conscious (wraps the bot)
        self.conscious = EnhancedConsciousMind(self.mem, self.subconscious, self.memory_path)

        # wire deferred ask_callable now that conscious exists
        self.subconscious.ask_callable = lambda q: self.conscious.bot.chat(q)

        # presence
        self.enable_presence = enable_presence
        self.presence: Optional[PersistentPresenceLayer] = None
        if self.enable_presence:
            self.presence = PersistentPresenceLayer(
                conscious=self.conscious,
                subconscious=self.subconscious,
                mode_mgr=self.mode_mgr,
                speak_cb=lambda text: print(f"[presence] {text}"),
                desire_threshold=0.55,     # a hair more talkative by default
                min_gap_seconds=75,
                quiet_hours_local=None     # e.g., (2, 6) to keep quiet overnight
            )

        # optional harvester (off by default; you can drive it externally)
        self.harvester = None
        if HARVESTER_AVAILABLE:
            try:
                self.harvester = AutonomousKnowledgeHarvester(memory_path=self.memory_path)
            except Exception:
                self.harvester = None

        self._threads_started = False

    def start(self):
        if self._threads_started:
            return
        self._threads_started = True
        self.subconscious.start()
        if self.presence:
            self.presence.start()

    def stop(self):
        if self.presence:
            self.presence.stop()
        self.subconscious.stop()

    # ---- public API ----
    def handle_user_input(self, text: str) -> str:
        # user interaction resets idle timer and ensures LIVE_USER mode
        self.mode_mgr.user_interaction_detected()
        if self.mode_mgr.current_mode != CognitiveMode.LIVE_USER:
            self.mode_mgr.transition_to(CognitiveMode.LIVE_USER)
        out = self.conscious.chat_with_user(text)
        # opportunistic autosave
        try:
            self.mem.save(self.memory_path)
        except Exception:
            pass
        return out

    def tick(self):
        """
        Drive mode transitions if you’re not running a full UI loop.
        Call periodically in your app loop.
        """
        if self.mode_mgr.should_transition_to_study():
            self.mode_mgr.transition_to(CognitiveMode.SOLITARY_STUDY)
        if self.mode_mgr.should_exit_study():
            self.mode_mgr.transition_to(CognitiveMode.ACTIVE_LEARNING)
        # optional: one step of harvester between ticks (lightweight)
        # if self.harvester:
        #     self._harvester_step()

    def conduct_study(self) -> dict:
        # Force a study pass (e.g., on a schedule)
        old, _ = self.mode_mgr.transition_to(CognitiveMode.SOLITARY_STUDY)
        res = self.conscious.conduct_study_session()
        self.mode_mgr.transition_to(old or CognitiveMode.LIVE_USER)
        return res

    def _harvester_step(self):
        """One concept step to gently grow knowledge (if harvester is wired)."""
        if not self.harvester:
            return
        try:
            # If queue exists, process next; else seeding happens internally
            if self.harvester.concept_queue:
                concept = self.harvester.concept_queue.pop(0)
                self.harvester.process_concept(concept)
            # Save harvester state periodically
            self.harvester.save_state()
        except Exception:
            pass


