class EnhancedSubconsciousMind(threading.Thread):
    DAEMON_INTERVAL = 1.0  # seconds
    MAX_LOG_LINES   = 20000
    EVOLVE_EVERY_S  = 20    # run evolution sweep roughly every 20s

    def __init__(self, memory: Memory, mode_manager: CognitiveModeManager, log_path: str,
                 ask_callable: Callable[[str], str], save_callable: Callable[[], None]):
        super().__init__(daemon=True)
        self.memory = memory
        self.mode_manager = mode_manager
        self.log_path = log_path
        self._stop = threading.Event()

        self.ask_callable = ask_callable        # bridge to conscious
        self.save_callable = save_callable      # force-persist changes

        # Queues & observations
        self.attention_queue = queue.Queue()
        self.practice_queue = queue.Queue()
        self.observations: List[dict] = []

        # Weakness tracking
        self.weak_concepts: set[str] = set()
        self.missing_facets: Dict[str, List[str]] = {}  # concept -> missing facets
        self.poor_connections: set[str] = set()

        # logging
        self._log_lock = threading.Lock()
        self._line_count = 0

        # timers
        self._last_evolve = 0.0

    # ---------- logging ----------
    def _log(self, kind: str, payload: dict):
        rec = {"t": now_iso(), "kind": kind, **payload}
        line = json.dumps(rec, ensure_ascii=False)
        try:
            with self._log_lock:
                with open(self.log_path, "a", encoding="utf-8") as f:
                    f.write(line + "\n")
                self._line_count += 1
                if self._line_count >= self.MAX_LOG_LINES:
                    self._rotate()
        except Exception:
            pass

    def _rotate(self):
        try:
            base, _ = os.path.splitext(self.log_path)
            rotated = f"{base}.{int(time.time())}.log"
            os.replace(self.log_path, rotated)
            self._line_count = 0
            self._log("rotate", {"to": rotated})
        except Exception:
            pass

    # ---------- thread core ----------
    def run(self):
        self._log("start", {"msg": "subconscious online"})
        try:
            while not self._stop.is_set():
                mode = self.mode_manager.current_mode
                if mode == CognitiveMode.LIVE_USER:
                    self._live_user_processing()
                elif mode == CognitiveMode.ACTIVE_LEARNING:
                    self._active_learning_processing()
                elif mode == CognitiveMode.SOLITARY_STUDY:
                    self._solitary_study_processing()

                # Probing cycle
                self._probe_cycle()

                # Evolution (subconscious-only ownership)
                if time.time() - self._last_evolve >= self.EVOLVE_EVERY_S:
                    promoted = self._evolve_active_concepts(limit=25)
                    if promoted:
                        self._log("evolve", {"promoted": promoted})
                        self.save_callable()  # persist promotions
                    self._last_evolve = time.time()

                time.sleep(self.DAEMON_INTERVAL)
        except Exception as e:
            self._log("error", {"msg": str(e)})
        finally:
            self._log("stop", {"msg": "subconscious offline"})

    def stop(self):
        self._stop.set()

    # ---------- integrated behavior ----------
    def _get_recently_accessed_crystals(self, limit: int = 10):
        items = list(self.memory.crystals.values())
        items.sort(key=lambda c: c.last_accessed, reverse=True)
        return items[:limit]

    def _identify_missing_facets(self, c) -> List[str]:
        missing = []
        L = int(getattr(c, "evolution_level", 1))
        if L >= 2:
            for facet in ("example", "operation", "abstract"):
                try:
                    if not c.get_facet(facet):
                        missing.append(facet)
                except Exception:
                    pass
        if L >= 3:
            for facet in ("cause", "effect", "temporal", "spatial"):
                try:
                    if not c.get_facet(facet):
                        missing.append(facet)
                except Exception:
                    pass
        return missing

    def _assess_concept_priority(self, c) -> str:
        if c.usage_count > 5 and len(self._identify_missing_facets(c)) > 2:
            return "HIGH"
        if len(c.connections) > 8:
            try:
                if not c.get_facet("definition"):
                    return "HIGH"
            except Exception:
                pass
        if c.usage_count > 2 and self._identify_missing_facets(c):
            return "MEDIUM"
        return "LOW"

    def _suggest_focus_areas(self, c) -> List[str]:
        out = []
        missing = self._identify_missing_facets(c)
        if "definition" in missing: out.append("needs clear definition")
        if "example" in missing:    out.append("needs concrete examples")
        if "cause" in missing:      out.append("needs causal relationships")
        if len(c.connections) < 3:  out.append("needs more connections to related concepts")
        return out

    def _live_user_processing(self):
        recent = self._get_recently_accessed_crystals(limit=10)
        for c in recent:
            missing = self._identify_missing_facets(c)
            if missing:
                self.missing_facets[c.concept] = missing
            if len(c.connections) < 2:
                self.poor_connections.add(c.concept)

    def _active_learning_processing(self):
        recent = self._get_recently_accessed_crystals(limit=5)
        for c in recent:
            pri = self._assess_concept_priority(c)
            if pri in ("HIGH", "MEDIUM"):
                self.attention_queue.put({
                    "concept": c.concept,
                    "priority": pri,
                    "reason": "Critical gap" if pri == "HIGH" else "Strengthen knowledge",
                    "suggested_focus": self._suggest_focus_areas(c)
                })
        self._log("learning_guidance", {
            "evaluated": len(recent),
            "flagged": sum(1 for c in recent if self._assess_concept_priority(c) == "HIGH")
        })

    def _solitary_study_processing(self):
        q = self._generate_practice_questions()
        for item in q:
            self.practice_queue.put(item)
        if self.observations: self.observations.clear()
        if len(self.weak_concepts) > 20: self.weak_concepts.clear()
        if len(self.missing_facets) > 15: self.missing_facets.clear()
        self._log("study_session", {
            "weak_concepts": len(self.weak_concepts),
            "missing_facets": len(self.missing_facets),
            "queued": self.practice_queue.qsize()
        })

    def _generate_practice_questions(self) -> List[str]:
        out: List[str] = []
        for concept in list(self.weak_concepts)[:5]:
            out += [f"what is {concept}?", f"how does {concept} work?",
                    f"what are examples of {concept}?", f"how does {concept} relate to other concepts?"]
        for concept, missing in list(self.missing_facets.items())[:3]:
            if "cause" in missing:     out.append(f"what causes {concept}?")
            if "operation" in missing: out.append(f"how does {concept} operate?")
        return out[:10]

    # ---------- probes ----------
    def _hot_crystals(self, limit=30):
        items = list(self.memory.crystals.values())
        items.sort(key=lambda c: (len(getattr(c, "connections", {}) or {})) + getattr(c, "usage_count", 0),
                   reverse=True)
        return items[:limit]

    def _check_L2_abstract(self, c):
        try:
            L = int(getattr(c, "evolution_level", 1))
        except Exception:
            L = 1
        if L >= 2:
            missing = []
            for role in ("abstract", "operation", "example", "relation"):
                try:
                    if not c.get_facet(role):
                        missing.append(role)
                except Exception:
                    pass
            if missing:
                try:
                    cid_cl = self.memory.ensure_concept("clarification", level=2)
                    self.memory.link(c.id, cid_cl, w=1)
                except Exception:
                    pass
                self._log("l2_missing", {"concept": c.concept, "missing": missing})

    def _check_L4_foresight(self, c):
        try:
            L = int(getattr(c, "evolution_level", 1))
        except Exception:
            L = 1
        if L >= 4:
            need = []
            for fac in ("I_coherence", "I_bridge", "O_plan"):
                try:
                    if not c.get_facet(fac):
                        need.append(fac)
                except Exception:
                    need.append(fac)
            if need:
                self._log("l4_missing", {"concept": c.concept, "need": need})

    def _make_probes(self, hot, limit=4) -> List[str]:
        out = []
        for c in hot:
            name = c.concept
            L = int(getattr(c, "evolution_level", 1))
            out.append(
                f"what is {name}?" if L == 1 else
                (f"how to use {name}" if L == 2 else
                 (f"why {name}?" if L == 3 else
                  f"when does {name} apply?"))
            )
            if len(out) >= limit:
                break
        return out

    def _evaluate_coherence(self, qtext: str, answer: str):
        coh = bool(re.search(r"\bmeans\b|\brelates to\b|\boccurs\b|\bbecause\b|\bfor example\b", answer, re.I))
        if not coh:
            self._log("eval_incoherent", {"q": qtext, "a": answer})
            toks = re.findall(r"[A-Za-z0-9_\-]+", qtext.lower())
            for t in toks:
                target_cid = None
                for cid, cc in self.memory.crystals.items():
                    if cc.concept.lower() == t:
                        target_cid = cid
                        break
                if target_cid:
                    c = self.memory.get(target_cid)
                    c.usage_count = getattr(c, "usage_count", 0) + 1
                    break
        else:
            self._log("eval_ok", {"q": qtext, "a": answer})

    def _probe_cycle(self):
        hot = self._hot_crystals(limit=30)
        for c in hot:
            self._check_L2_abstract(c)
            self._check_L4_foresight(c)
        for p in self._make_probes(hot, limit=4):
            try:
                a = self.ask_callable(p)
                self._evaluate_coherence(p, a)
            except Exception as e:
                self._log("probe_error", {"q": p, "err": str(e)})

    # ---------- subconscious-owned evolution ----------
    def _evolve_active_concepts(self, limit: int = 25) -> int:
        """Promote crystals based on facets + connectivity. Returns number promoted."""
        try:
            items = list(self.memory.crystals.values())
        except Exception:
            return 0
        items.sort(key=lambda c: getattr(c, "usage_count", 0) + len(getattr(c, "connections", {}) or {}), reverse=True)
        promoted = 0
        for c in items[:limit]:
            try:
                L = int(getattr(c, "evolution_level", 1))
            except Exception:
                L = 1
            has_def = bool(c.get_facet("definition"))
            has_ex  = bool(c.get_facet("example"))
            has_op  = bool(c.get_facet("operation") or c.get_facet("process"))
            has_cau = bool(c.get_facet("cause"))
            degree  = len(getattr(c, "connections", {}) or {})
            target = L
            if has_def and (has_ex or has_op):
                target = max(target, 2)
            if has_def and has_op and (has_cau or degree >= 3):
                target = max(target, 3)
            if L >= 3 and degree >= 6 and has_def and has_op:
                target = max(target, 4)
            if target > L:
                c.evolution_level = target
                promoted += 1
        return promoted


