class CognitiveModeManager:
    def __init__(self):
        self.current_mode = CognitiveMode.LIVE_USER
        self.mode_start_time = time.time()
        self.user_idle_threshold = 300      # 5 min
        self.study_session_duration = 600   # 10 min
        self.last_user_interaction = time.time()

    def should_transition_to_study(self) -> bool:
        idle_time = time.time() - self.last_user_interaction
        return (self.current_mode == CognitiveMode.LIVE_USER and idle_time > self.user_idle_threshold)

    def should_exit_study(self) -> bool:
        study_time = time.time() - self.mode_start_time
        return (self.current_mode == CognitiveMode.SOLITARY_STUDY and study_time > self.study_session_duration)

    def transition_to(self, mode: CognitiveMode):
        if mode != self.current_mode:
            old = self.current_mode
            self.current_mode = mode
            self.mode_start_time = time.time()
            return old, mode
        return None, None

    def user_interaction_detected(self):
        self.last_user_interaction = time.time()
        if self.current_mode != CognitiveMode.LIVE_USER:
            return self.transition_to(CognitiveMode.LIVE_USER)
        return None, None


