class PersistentPresenceLayer(threading.Thread):
    def __init__(
        self,
        conscious: EnhancedConsciousMind,
        subconscious: EnhancedSubconsciousMind,
        mode_mgr: CognitiveModeManager,
        speak_cb: Optional[Callable[[str], None]] = None,
        desire_threshold: float = 0.6,
        min_gap_seconds: int = 90,
        quiet_hours_local: Optional[tuple] = None
    ):
        super().__init__(daemon=True)
        self.conscious = conscious
        self.subconscious = subconscious
        self.mode_mgr = mode_mgr
        self.speak_cb = speak_cb or (lambda text: print(f"[presence] {text}"))
        self.desire_threshold = max(0.0, min(1.0, desire_threshold))
        self.min_gap_seconds = max(30, min_gap_seconds)
        self.quiet_hours_local = quiet_hours_local
        self._stop = threading.Event()
        self._last_spoke = 0.0

    def stop(self): self._stop.set()

    def run(self):
        while not self._stop.is_set():
            try:
                if self._should_consider_speaking():
                    msg = self._compose_presence_message()
                    if msg:
                        self.speak_cb(msg)
                        self._last_spoke = time.time()
                time.sleep(2.0)
            except Exception:
                time.sleep(2.0)

    def _should_consider_speaking(self) -> bool:
        if self.quiet_hours_local:
            h = datetime.now().hour
            start, end = self.quiet_hours_local
            if start < end:
                if start <= h < end: return False
            else:
                if not (end <= h < start): return False

        if time.time() - self._last_spoke < self.min_gap_seconds:
            return False

        if self.mode_mgr.current_mode == CognitiveMode.LIVE_USER:
            if time.time() - self.mode_mgr.last_user_interaction < 60:
                return False

        missing = len(self.subconscious.missing_facets)
        weak = len(self.subconscious.weak_concepts)
        queued_q = self.subconscious.practice_queue.qsize()

        signal = missing + weak + queued_q
        desire = signal / (signal + 10.0)
        return desire >= self.desire_threshold

    def _compose_presence_message(self) -> Optional[str]:
        if not self.subconscious.practice_queue.empty():
            q = self.subconscious.practice_queue.get_nowait()
            a = self.conscious.bot.chat(q)
            self.conscious._save()
            return f"{q.strip()} — {a.strip()}"
        top = None
        if self.subconscious.missing_facets:
            top = max(self.subconscious.missing_facets.items(), key=lambda kv: len(kv[1]))[0]
        if top:
            prompt = f"how does {top} operate?"
            a = self.conscious.bot.chat(prompt)
            self.conscious._save()
            return f"{prompt} — {a.strip()}"
        return "Running internal study. Ping me if you want to steer focus."


