    def __init__(self, memory_path: Optional[str] = None, log_path: Optional[str] = None,
                 enable_presence: bool = True, conversation_bias: bool = True):
        self.memory_path = memory_path or default_mem_path()
        self.log_path = log_path or self.memory_path.replace(".json", "_cognitive.log")

        # memory
        self.mem = Memory.load(self.memory_path)
        self.mem.path = self.memory_path
        self.mem.autosave = True
        migrate_facets(self.mem)

        # mode manager
        self.mode_mgr = CognitiveModeManager()

        # subconscious (bridge asks conscious later)
        self.subconscious = EnhancedSubconsciousMind(
            memory=self.mem,
            mode_manager=self.mode_mgr,
            log_path=self.log_path,
            ask_callable=lambda q: self.conscious.bot.chat(q),     # assign after conscious exists
            save_callable=lambda: self.mem.save(self.memory_path),
            conversation_bias=conversation_bias                    # <<— toggle wired in
        )

        # conscious
        self.conscious = EnhancedConsciousMind(self.mem, self.subconscious, self.memory_path)

        # wire callable now
        self.subconscious.ask_callable = lambda q: self.conscious.bot.chat(q)

        # presence
        self.enable_presence = enable_presence
        self.presence: Optional[PersistentPresenceLayer] = None
        if self.enable_presence:
            self.presence = PersistentPresenceLayer(
                conscious=self.conscious,
                subconscious=self.subconscious,
                mode_mgr=self.mode_mgr,
                speak_cb=lambda text: print(f"[presence] {text}"),
                desire_threshold=0.55,
                min_gap_seconds=75,
                quiet_hours_local=None
            )

        # Back-compat: instance attribute many runners expect
        self.guidance_adapter = SubconsciousGuidanceAdapter(self.mem, self.subconscious)

        # Do NOT run harvester here by default; evolution is subconscious-owned
        self.harvester = None
        if HARVESTER_AVAILABLE and os.environ.get("RUN_HARVESTER_WITH_MIND", "0") == "1":
            try:
                self.harvester = AutonomousKnowledgeHarvester(memory_path=self.memory_path, guidance=self.guidance_adapter)
            except Exception:
                self.harvester = None

        self._threads_started = False

    # Public toggle control
    def set_conversation_bias(self, on: bool):
        self.subconscious.conversation_bias = bool(on)

    def start(self):
        if self._threads_started: return
        self._threads_started = True
        self.subconscious.start()
        if self.presence: self.presence.start()

    def stop(self):
        if self.presence: self.presence.stop()
        self.subconscious.stop()
        try:
            self.mem.save(self.memory_path)
        except Exception:
            pass

    # ---- public API ----
    def handle_user_input(self, text: str) -> str:
        self.mode_mgr.user_interaction_detected()
        if self.mode_mgr.current_mode != CognitiveMode.LIVE_USER:
            self.mode_mgr.transition_to(CognitiveMode.LIVE_USER)
        out = self.conscious.chat_with_user(text)
        try:
            self.mem.save(self.memory_path)
        except Exception:
            pass
        return out

    def tick(self):
        if self.mode_mgr.should_transition_to_study():
            self.mode_mgr.transition_to(CognitiveMode.SOLITARY_STUDY)
        if self.mode_mgr.should_exit_study():
            self.mode_mgr.transition_to(CognitiveMode.ACTIVE_LEARNING)

    def conduct_study(self) -> dict:
        old, _ = self.mode_mgr.transition_to(CognitiveMode.SOLITARY_STUDY)
        res = self.conscious.conduct_study_session()
        self.mode_mgr.transition_to(old or CognitiveMode.LIVE_USER)
        try:
            self.mem.save(self.memory_path)
        except Exception:
            pass
        return res


