# ------------------ Utilities ------------------

def _norm(s: str) -> str:
    return re.sub(r"\s+", " ", (s or "").strip())

def _now() -> float:
    return time.time()

def _sentences(txt: str) -> List[str]:
    # crude sentence split that’s robust for summaries
    return [s.strip() for s in re.split(r'(?<=[.!?])\s+', (txt or '').strip()) if s.strip()]

def _pick_example(extract: str) -> Optional[str]:
    # grab a sentence with e.g. "for example", or the second sentence as a fallback
    ss = _sentences(extract)
    for s in ss:
        if re.search(r'\b(for example|e\.g\.)\b', s, re.I):
            return s[:400]
    return ss[1][:400] if len(ss) > 1 else (ss[0][:400] if ss else None)

def _pick_operation(extract: str) -> Optional[str]:
    # heuristics for "operation/process" phrasing
    ss = _sentences(extract)
    for s in ss:
        if re.search(r'\b(process|method|procedure|works by|involves|consists of)\b', s, re.I):
            return s[:500]
    return None

def _pick_cause(extract: str) -> Optional[str]:
    ss = _sentences(extract)
    for s in ss:
        if re.search(r'\b(because|due to|caused by|arises from|results from)\b', s, re.I):
            return s[:500]
    return None

# ------------------ Wikipedia Client ------------------

class WikiClient:
    def __init__(self, lang: str = "en", timeout: float = 8.0, rpm: int = 60):
        self.lang = lang
        self.timeout = timeout
        self.session = requests.Session()
        self.session.headers.update({
            "User-Agent": "CrystalHarvester/1.0 (contact: local-runner)",
            "Accept": "application/json"
        })
        self.min_interval = 60.0 / max(1, rpm)
        self._last_call = 0.0

    def _pace(self):
        dt = time.time() - self._last_call
        if dt < self.min_interval:
            time.sleep(self.min_interval - dt)
        self._last_call = time.time()

    def _get(self, path: str, params: dict = None):
        self._pace()
        url = f"https://{self.lang}.wikipedia.org/api/rest_v1{path}"
        try:
            r = self.session.get(url, params=params or {}, timeout=self.timeout)
            if r.status_code == 404:
                return None
            r.raise_for_status()
            return r.json()
        except Exception:
            return None

    def summary(self, title: str) -> Optional[dict]:
        # /page/summary/{title}
        safe = title.replace(" ", "_")
        return self._get(f"/page/summary/{safe}")

    def related(self, title: str) -> List[str]:
        # /page/related/{title} → extract titles
        safe = title.replace(" ", "_")
        j = self._get(f"/page/related/{safe}")
        out = []
        try:
            for item in (j.get("pages") or []):
                t = item.get("titles", {}).get("normalized") or item.get("title") or ""
                if t: out.append(_norm(t))
        except Exception:
            pass
        return list(dict.fromkeys(out))[:20]

    def search_first(self, query: str) -> Optional[str]:
        # fallback via MediaWiki search API to get canonical title
        self._pace()
        try:
            r = self.session.get(
                f"https://{self.lang}.wikipedia.org/w/api.php",
                params={
                    "action": "opensearch",
                    "search": query,
                    "limit": 1,
                    "namespace": 0,
                    "format": "json"
                },
                timeout=self.timeout
            )
            r.raise_for_status()
            data = r.json()
            if data and len(data) >= 2 and data[1]:
                return _norm(data[1][0])
        except Exception:
            pass
        return None

# ------------------ Harvester ------------------

@dataclass
class AutonomousKnowledgeHarvester:
    memory_path: str = "memory_fractal.json"
    state_file: str = "harvester_state.json"
    guidance: object = None                 # optional: allow_candidate/score_candidate/focus_facets
    allow_evolution: bool = False           # evolution OFF — subconscious owns it
    lang: str = "en"
    rpm: int = 60                           # requests per minute cap

    # runtime
    mem: Memory = field(init=False)
    bot: FractalCrystalBot = field(init=False)
    wiki: WikiClient = field(init=False)
    concept_queue: List[str] = field(default_factory=list, init=False)
    discovered_concepts: set = field(default_factory=set, init=False)
    last_persist: float = field(default=0.0, init=False)

    def __post_init__(self):
        # Memory
        self.mem = Memory.load(self.memory_path)
        self.mem.path = self.memory_path
        self.mem.autosave = True
        migrate_facets(self.mem)

        self.bot = FractalCrystalBot(self.mem)
        self.wiki = WikiClient(lang=self.lang, rpm=self.rpm)

        self._load_state()

        if not self.concept_queue:
            self._initialize_from_existing_memory()

    # ------------------ State I/O ------------------

    def _load_state(self):
        try:
            if os.path.exists(self.state_file):
                with open(self.state_file, "r", encoding="utf-8") as f:
                    st = json.load(f)
                self.concept_queue = list(st.get("concept_queue", []))
                self.discovered_concepts = set(st.get("discovered_concepts", []))
        except Exception:
            pass

    def _save_state(self):
        try:
            st = {
                "concept_queue": list(self.concept_queue),
                "discovered_concepts": list(self.discovered_concepts),
                "ts": _now(),
            }
            with open(self.state_file, "w", encoding="utf-8") as f:
                json.dump(st, f, ensure_ascii=False, indent=2)
        except Exception:
            pass

    def _persist(self, force: bool = False):
        if force or (_now() - self.last_persist) > 3.0:
            try:
                self.mem.path = self.memory_path
                self.mem.save(self.memory_path)
            except Exception:
                pass
            self._save_state()
            self.last_persist = _now()

    # ------------------ Stats / Status ------------------

    def _stats(self) -> Dict[str, int]:
        crystals = list(self.mem.crystals.values())
        total = len(crystals)
        l1 = l2 = l3 = l4 = 0
        defn = ex = op = cau = 0
        edges = 0
        for c in crystals:
            try:
                L = int(getattr(c, "evolution_level", 1))
            except Exception:
                L = 1
            if L <= 1: l1 += 1
            elif L == 2: l2 += 1
            elif L == 3: l3 += 1
            else: l4 += 1
            try:
                if c.get_facet("definition"): defn += 1
            except Exception: pass
            try:
                if c.get_facet("example"): ex += 1
            except Exception: pass
            try:
                if c.get_facet("operation") or c.get_facet("process"): op += 1
            except Exception: pass
            try:
                if c.get_facet("cause"): cau += 1
            except Exception: pass
            edges += len(getattr(c, "connections", {}) or {})
        edges //= 2
        return {
            "crystals_total": total,
            "L1": l1, "L2": l2, "L3": l3, "L4": l4,
            "with_definition": defn, "with_example": ex,
            "with_operation": op, "with_cause": cau,
            "edges": edges, "queue": len(self.concept_queue),
            "discovered": len(self.discovered_concepts),
        }

    def report_status(self, print_it: bool = True) -> Dict[str, int]:
        st = self._stats()
        if print_it:
            line = (
                f"[harvester] crystals={st['crystals_total']} "
                f"L1={st['L1']} L2={st['L2']} L3={st['L3']} L4={st['L4']} | "
                f"def={st['with_definition']} ex={st['with_example']} "
                f"op={st['with_operation']} cause={st['with_cause']} | "
                f"edges={st['edges']} queue={st['queue']} discovered={st['discovered']}"
            )
            print(line, flush=True)
        return st

    # ------------------ Seeding ------------------

    def _initialize_from_existing_memory(self):
        # You can tweak seeds; these keep convo-friendly concepts near the surface
        seed_concepts = [
            "Language", "Communication", "Dialogue", "Grammar",
            "Cognition", "Intelligence", "Consciousness",
            "Learning", "Memory", "Reasoning", "Information", "Concept"
        ]
        chosen: List[Tuple[float, str]] = []
        for concept in seed_concepts:
            if self.guidance and hasattr(self.guidance, "allow_candidate"):
                if not self.guidance.allow_candidate(concept, source="seed"): 
                    continue
            score = 0.5
            if self.guidance and hasattr(self.guidance, "score_candidate"):
                try:
                    score = float(self.guidance.score_candidate(concept, source="seed"))
                except Exception:
                    pass
            chosen.append((score, concept))
        chosen.sort(reverse=True)
        for _, concept in chosen:
            if concept not in self.discovered_concepts:
                self.concept_queue.append(concept)
                self.discovered_concepts.add(concept)

        self._persist(force=True)
        self._json_log_step(step=0, concept="__init__", ok=True)
        self.report_status(print_it=True)

    # ------------------ Wikipedia Integration ------------------

    def _fetch_summary_and_related(self, title: str) -> Tuple[Optional[dict], List[str]]:
        # Try direct summary
        j = self.wiki.summary(title)
        if not j:
            # Try a search to canonicalize the title
            best = self.wiki.search_first(title)
            if best:
                j = self.wiki.summary(best)
                title = best if j else title
        related = self.wiki.related(j.get("title", title) if j else title) if title else []
        return j, related

    # ------------------ Integration into Memory ------------------

    def _integrate_from_wiki(self, concept_name: str, summary_json: dict):
        """
        Map Wikipedia summary → facets: definition, example, operation, cause.
        """
        title = _norm(summary_json.get("title") or concept_name).lower()
        extract = summary_json.get("extract") or ""
        desc = summary_json.get("description") or ""
        definition = extract if extract else desc

        cid = self.mem.ensure_concept(title, content=(definition or ""), level=2)
        c = self.mem.get(cid)

        if definition:
            c.set_facet("definition", definition[:1000])
        ex = _pick_example(extract)
        if ex:
            c.set_facet("example", ex)
        op = _pick_operation(extract)
        if op:
            c.set_facet("operation", op)
        cau = _pick_cause(extract)
        if cau:
            c.set_facet("cause", cau)

        # Touch and persist
        c.touch()
        self._persist(force=True)

    # ------------------ Per-concept processing ------------------

    def process_concept(self, concept: str) -> bool:
        name = _norm(concept)
        if not name:
            return False

        # Wikipedia fetch
        j, related_titles = self._fetch_summary_and_related(name)
        if j:
            self._integrate_from_wiki(name, j)
        else:
            # Couldn’t fetch; create a placeholder concept so we don't loop forever
            cid = self.mem.ensure_concept(name.lower(), content="", level=1)
            c = self.mem.get(cid)
            c.touch()
            self._persist(force=True)

        # Expand queue with related (guided + deduped)
        if related_titles:
            ranked: List[Tuple[float, str]] = []
            for t in related_titles:
                t_norm = _norm(t)
                if not t_norm:
                    continue
                if self.guidance and hasattr(self.guidance, "allow_candidate"):
                    try:
                        if not self.guidance.allow_candidate(t_norm, source=f"wiki:{name}"):
                            continue
                    except Exception:
                        pass
                sc = 0.5
                if self.guidance and hasattr(self.guidance, "score_candidate"):
                    try:
                        sc = float(self.guidance.score_candidate(t_norm, source=f"wiki:{name}"))
                    except Exception:
                        pass
                ranked.append((sc, t_norm))
            ranked.sort(reverse=True)
            for _, t in ranked[:15]:
                if t not in self.discovered_concepts:
                    self.discovered_concepts.add(t)
                    self.concept_queue.append(t)

        self._persist()
        return True

    # ------------------ Evolution (disabled) ------------------

    def _evolve_active_concepts(self, *args, **kwargs) -> int:
        """No-op: evolution belongs to the subconscious. Kept for compatibility."""
        return 0

    # ------------------ JSON log helper ------------------

    def _json_log_step(self, step: int, concept: str, ok: bool, log_file: str = "harvester_activity.log"):
        payload = {
            "t": _now(),
            "step": step,
            "concept": concept,
            "ok": bool(ok),
            "stats": self._stats()
        }
        try:
            with open(log_file, "a", encoding="utf-8") as f:
                f.write(json.dumps(payload, ensure_ascii=False) + "\n")
        except Exception:
            pass

    # ------------------ Main loop ------------------

    def autonomous_discovery_loop(
        self,
        max_steps: Optional[int] = None,
        sleep_s: float = 0.0,
        verbose: bool = True,
        status_every: int = 1,
        log_file: str = "harvester_activity.log"
    ):
        """
        Processes concepts from the queue with real Wikipedia pulls.
        Logs JSON lines each step + optional console status.
        No evolution is performed here.
        """
        steps = 0
        if verbose:
            print("[harvester] starting loop", flush=True)

        while True:
            if max_steps is not None and steps >= max_steps:
                break
            if not self.concept_queue:
                self._persist()
                if verbose:
                    print("[harvester] queue empty", flush=True)
                break

            concept = self.concept_queue.pop(0)
            try:
                ok = self.process_concept(concept)
            except Exception:
                ok = False

            steps += 1

            # JSON log (always)
            self._json_log_step(step=steps, concept=concept, ok=ok, log_file=log_file)

            # Console echo (optional)
            if verbose and (steps % max(1, status_every) == 0):
                st = self._stats()
                line = (
                    f"[harvester] step={steps} concept='{concept}' ok={ok} | "
                    f"crystals={st['crystals_total']} "
                    f"L1={st['L1']} L2={st['L2']} L3={st['L3']} L4={st['L4']} | "
                    f"def={st['with_definition']} ex={st['with_example']} "
                    f"op={st['with_operation']} cause={st['with_cause']} | "
                    f"edges={st['edges']} queue={st['queue']} discovered={st['discovered']}"
                )
                print(line, flush=True)

            if sleep_s > 0:
                time.sleep(sleep_s)

        self._persist(force=True)
        if verbose:
            print("[harvester] loop complete", flush=True)
            self._json_log_step(step=steps, concept="__complete__", ok=True, log_file=log_file)
```

### Notes
- Uses **Wikipedia REST** (`/page/summary/{title}` + `/page/related/{title}`) with a sane **User-Agent** and rate limit (RPM).
- Lightweight facet extraction from the summary (better than nothing) while staying **real** to source.
- **Evolution stays off**; subconscious handles that.
- Saves to **your memory JSON** every write; logs to `harvester_activity.log` each step.

