                score = 0.5
                if self.guidance and hasattr(self.guidance, "score_candidate"):
                    try:
                        score = float(self.guidance.score_candidate(t_norm, source=f"wiki:{concept}"))
                    except Exception:
                        pass
                # insert by score (simple: append; we sort once at the end)
                self.discovered_concepts.add(t_norm)
                self.concept_queue.append((score, t_norm))
                added += 1

            # one-pass sort high→low if we inserted scored tuples
            if self.concept_queue and isinstance(self.concept_queue[0], tuple):
                self.concept_queue.sort(key=lambda x: x[0], reverse=True)
                self.concept_queue = [name for _, name in self.concept_queue]

            # JSON log (always)
            self._json_log_step(step=steps, concept=concept, ok=ok, log_file=log_file,
                                skip_reason=reason or (f"skipped:{skipped}" if skipped else ""))

            # Console echo (optional)
            if verbose and (steps % max(1, status_every) == 0):
                st = self._stats()
                print(
                    f"[harvester] step={steps} concept='{concept}' ok={ok} added={added} "
                    f"(skipped={skipped}, starving={starving}) | "
                    f"crystals={st['crystals_total']} L1={st['L1']} L2={st['L2']} L3={st['L3']} L4={st['L4']} | "
                    f"def={st['with_definition']} ex={st['with_example']} op={st['with_operation']} cause={st['with_cause']} | "
                    f"edges={st['edges']} queue={st['queue']} discovered={st['discovered']}",
                    flush=True
                )

            if sleep_s > 0:
                time.sleep(sleep_s)

        # final evolve pulse + save
        if self._maybe_subconscious_evolve(limit=30):
            self._persist(force=True)
        else:
            self._persist(force=True)

        if verbose:
            print("[harvester] loop complete", flush=True)

    # compatibility: harvester never evolves
    def _evolve_active_concepts(self, *args, **kwargs) -> int:
        return 0
