### TL;DR for you
- It emptied because **related links were thin** and/or **guidance filtered too hard**.  
- Now it **falls back to full outgoing links** via the action API and **softens** filtering when the queue is starving, so it keeps growing.  
- Subconscious still does the **evolve**—every write and on periodic pulses.

If it *still* stops early, tell me the last few console lines (you’ll see `added=… (skipped=… , starving=…)` and `skip_reason` in the JSON log). I’ll use those to tighten whichever path is starving your queue.

Here it is—**drop-in replacement** for `autonomous_harvester.py` with:
- real Wikipedia pulls (REST + action API fallback),
- resilient link expansion (related → outgoing links with continuation),
- **subconscious-driven evolution** via `evolve_cb` (harvester never promotes itself),
- JSON-line logging + optional console status,
- hard saves to `memory_fractal.json`.

```python
# autonomous_harvester.py — Wikipedia-backed harvester (robust) + subconscious-driven evolution
from __future__ import annotations

import os, re, json, time
from dataclasses import dataclass, field
from typing import List, Dict, Optional, Tuple, Callable, Set

import requests  # pip install requests

from crystal_engine_v3 import Memory, migrate_facets
from chatbot_core_v3 import FractalCrystalBot

# ------------------ Small utils ------------------

def _norm(s: str) -> str:
    return re.sub(r"\s+", " ", (s or "").strip())

def _now() -> float:
    return time.time()

def _sentences(text: str) -> List[str]:
    parts = re.split(r"(?<=[.!?])\s+(?=[A-Z(])", text or "")
    return [p.strip() for p in parts if p.strip()]

def _cap(s: str, n: int) -> str:
    return s[:n] if s and len(s) > n else (s or "")

# ------------------ Wikipedia client ------------------

class WikiClient:
    def __init__(self, lang: str = "en", timeout: float = 10.0, rpm: int = 60):
        self.lang = lang
        self.timeout = timeout
        self.session = requests.Session()
        self.session.headers.update({
            "User-Agent": "CrystalHarvester/1.0 (local)",
            "Accept": "application/json"
        })
        self.min_interval = 60.0 / max(1, rpm)
        self._last_call = 0.0

    def _pace(self):
        dt = time.time() - self._last_call
        if dt < self.min_interval:
            time.sleep(self.min_interval - dt)
        self._last_call = time.time()

    def _get(self, url: str, params: dict = None):
        self._pace()
        r = self.session.get(url, params=params or {}, timeout=self.timeout)
        if r.status_code == 404:
            return None
        r.raise_for_status()
        return r.json()

    # REST
    def summary(self, title: str) -> Optional[dict]:
        safe = title.replace(" ", "_")
        url = f"https://{self.lang}.wikipedia.org/api/rest_v1/page/summary/{safe}"
        try:
            return self._get(url)
        except Exception:
            return None

    def related(self, title: str) -> List[str]:
        safe = title.replace(" ", "_")
        url = f"https://{self.lang}.wikipedia.org/api/rest_v1/page/related/{safe}"
        try:
            j = self._get(url) or {}
        except Exception:
            return []
        out = []
        for item in (j.get("pages") or []):
            t = (item.get("titles", {}) or {}).get("normalized") or item.get("title") or ""
            if t: out.append(_norm(t))
        return list(dict.fromkeys(out))[:50]

    # Action API fallbacks
    def extract_plain(self, title: str) -> str:
        url = f"https://{self.lang}.wikipedia.org/w/api.php"
        params = {
            "action": "query", "prop": "extracts", "explaintext": 1, "exlimit": 1,
            "redirects": 1, "titles": title, "format": "json"
        }
        try:
            j = self._get(url, params)
            pages = (j or {}).get("query", {}).get("pages", {}) or {}
            if not pages: return ""
            page = next(iter(pages.values()))
            return page.get("extract") or ""
        except Exception:
            return ""

    def links_outgoing(self, title: str, max_links: int = 300) -> List[str]:
        url = f"https://{self.lang}.wikipedia.org/w/api.php"
        params = {
            "action": "query", "prop": "links", "pllimit": "max",
            "redirects": 1, "titles": title, "format": "json"
        }
        links, cont = [], {}
        try:
            while True and len(links) < max_links:
                prms = dict(params); prms.update(cont)
                j = self._get(url, prms) or {}
                pages = j.get("query", {}).get("pages", {}) or {}
                if not pages: break
                page = next(iter(pages.values()))
                for ln in (page.get("links") or []):
                    t = ln.get("title") or ""
                    if t and not t.startswith(("Help:", "File:", "Template:", "Category:", "Portal:", "Talk:")):
                        links.append(_norm(t))
                cont_key = j.get("continue")
                if not cont_key: break
                cont = {"plcontinue": cont_key.get("plcontinue"), "continue": cont_key.get("continue")}
                if not cont["plcontinue"]: break
        except Exception:
            pass
        # dedup & trim
        out, seen = [], set()
        for t in links:
            if t not in seen:
                seen.add(t); out.append(t)
            if len(out) >= max_links: break
        return out

# ------------------ Facet extraction ------------------

def extract_structured(article_text: str) -> Dict[str, str]:
    text = article_text or ""
    sents = _sentences(text)

    definition = ""
    for s in sents[:8]:
        if re.search(r"\b(is|are|refers to|defined as)\b", s, re.I):
            definition = s; break
    if not definition and sents:
        definition = sents[0]

    ex_sents = [s for s in sents if re.search(r"\b(for example|such as|including|e\.g\.)\b", s, re.I)]
    examples = " ".join(ex_sents[:3])

    op_sents = [s for s in sents if re.search(r"\b(process|steps?|mechanism|method|works by|involves)\b", s, re.I)]
    operation = " ".join(op_sents[:2])

    cause_sents = [s for s in sents if re.search(r"\b(cause|causes|due to|because|arises from|results? from)\b", s, re.I)]
    cause = " ".join(cause_sents[:2])

    return {
        "definition": _cap(definition, 900),
        "examples": _cap(examples, 900),
        "operation": _cap(operation, 900),
        "cause": _cap(cause, 900),
    }

# ------------------ Harvester ------------------

@dataclass
class AutonomousKnowledgeHarvester:
    memory_path: str = "memory_fractal.json"
    state_file: str = "harvester_state.json"
    guidance: object = None                           # optional adapter with allow_candidate / score_candidate / focus_facets
    evolve_cb: Optional[Callable[[int], int]] = None  # subconscious hook: called after writes & periodically
    lang: str = "en"
    rpm: int = 60
    guidance_soft_mode: bool = True                   # if queue is starving, don't hard-block on guidance

    mem: Memory = field(init=False)
    bot: FractalCrystalBot = field(init=False)
    wiki: WikiClient = field(init=False)
    concept_queue: List[str] = field(default_factory=list, init=False)
    discovered_concepts: Set[str] = field(default_factory=set, init=False)
    last_persist: float = field(default=0.0, init=False)
    _last_sub_evolve: float = field(default=0.0, init=False)
    _sub_evolve_every_s: float = field(default=25.0, init=False)

    def __post_init__(self):
        # Memory
        self.mem = Memory.load(self.memory_path)
        self.mem.path = self.memory_path
        self.mem.autosave = True
        migrate_facets(self.mem)

        self.bot = FractalCrystalBot(self.mem)
        self.wiki = WikiClient(lang=self.lang, rpm=self.rpm)

        self._load_state()
        if not self.concept_queue:
            self._initialize_from_existing_memory()

    # -------- state I/O --------
    def _load_state(self):
        try:
            if os.path.exists(self.state_file):
                with open(self.state_file, "r", encoding="utf-8") as f:
                    st = json.load(f)
                self.concept_queue = list(st.get("concept_queue", []))
                self.discovered_concepts = set(st.get("discovered_concepts", []))
        except Exception:
            pass

    def _save_state(self):
        try:
            st = {
                "concept_queue": list(self.concept_queue),
                "discovered_concepts": list(self.discovered_concepts),
                "ts": _now(),
            }
            with open(self.state_file, "w", encoding="utf-8") as f:
                json.dump(st, f, ensure_ascii=False, indent=2)
        except Exception:
            pass

    def _persist(self, force: bool = False):
        if force or (_now() - self.last_persist) > 3.0:
            try:
                self.mem.path = self.memory_path
                self.mem.save(self.memory_path)
            except Exception:
                pass
            self._save_state()
            self.last_persist = _now()

    # -------- stats / logs --------
    def _stats(self) -> Dict[str, int]:
        crystals = list(self.mem.crystals.values())
        total = len(crystals)
        l1=l2=l3=l4=0; defn=ex=op=cau=0; edges=0
        for c in crystals:
            try: L = int(getattr(c, "evolution_level", 1))
            except Exception: L = 1
            if   L<=1: l1+=1
            elif L==2: l2+=1
            elif L==3: l3+=1
            else:      l4+=1
            try:
                if c.get_facet("definition"): defn+=1
            except Exception: pass
            try:
                if c.get_facet("example"): ex+=1
            except Exception: pass
            try:
                if c.get_facet("operation") or c.get_facet("process"): op+=1
            except Exception: pass
            try:
                if c.get_facet("cause"): cau+=1
            except Exception: pass
            edges += len(getattr(c, "connections", {}) or {})
        edges//=2
        return {
            "crystals_total": total, "L1": l1, "L2": l2, "L3": l3, "L4": l4,
            "with_definition": defn, "with_example": ex, "with_operation": op, "with_cause": cau,
            "edges": edges, "queue": len(self.concept_queue), "discovered": len(self.discovered_concepts),
        }

    def report_status(self, print_it: bool = True) -> Dict[str, int]:
        st = self._stats()
        if print_it:
            print(
                f"[harvester] crystals={st['crystals_total']} "
                f"L1={st['L1']} L2={st['L2']} L3={st['L3']} L4={st['L4']} | "
                f"def={st['with_definition']} ex={st['with_example']} "
                f"op={st['with_operation']} cause={st['with_cause']} | "
                f"edges={st['edges']} queue={st['queue']} discovered={st['discovered']}",
                flush=True
            )
        return st

    def _json_log_step(self, step: int, concept: str, ok: bool, log_file: str = "harvester_activity.log", skip_reason: str = ""):
        payload = {"t": _now(), "step": step, "concept": concept, "ok": bool(ok), "skip_reason": skip_reason, "stats": self._stats()}
        try:
            with open(log_file, "a", encoding="utf-8") as f:
                f.write(json.dumps(payload, ensure_ascii=False) + "\n")
        except Exception:
            pass

    # -------- seeding --------
    def _initialize_from_existing_memory(self):
        seed_concepts = [
            "Language","Communication","Dialogue","Grammar",
            "Cognition","Intelligence","Consciousness",
            "Learning","Memory","Reasoning","Information","Concept"
        ]
        ranked: List[Tuple[float,str]] = []
        for concept in seed_concepts:
            if self.guidance and hasattr(self.guidance, "allow_candidate"):
                try:
                    if not self.guidance.allow_candidate(concept, source="seed"):
                        continue
                except Exception:
                    pass
            score = 0.5
            if self.guidance and hasattr(self.guidance, "score_candidate"):
                try: score = float(self.guidance.score_candidate(concept, source="seed"))
                except Exception: pass
            ranked.append((score, concept))
        ranked.sort(reverse=True)
        for _, c in ranked:
            if c not in self.discovered_concepts:
                self.discovered_concepts.add(c)
                self.concept_queue.append(c)
        self._persist(force=True)
        self._json_log_step(step=0, concept="__init__", ok=True)
        self.report_status(print_it=True)

    # -------- wiki fetch / structure (with fallback) --------
    def _fetch_and_structure(self, title: str) -> Tuple[str, Dict[str,str]]:
        j = self.wiki.summary(title)
        text = ""
        page_title = ""
        if j:
            page_title = j.get("title") or title
            text = j.get("extract") or j.get("description") or ""
        if not text:
            # fallback to action API plain extract
            ext = self.wiki.extract_plain(title)
            if ext:
                page_title = page_title or title
                text = ext
        if not text:
            return "", {}
        return (page_title or title, extract_structured(text))

    def _related_links(self, title: str) -> List[str]:
        rel = self.wiki.related(title) or []
        if len(rel) >= 5:
            return rel[:50]
        # fallback to broader outgoing links
        outs = self.wiki.links_outgoing(title, max_links=300)
        out = []
        for t in outs:
            if re.match(r"^\d{3,4}$", t): continue  # skip plain years
            if len(t) < 3: continue
            out.append(_norm(t))
            if len(out) >= 150: break
        merged = list(dict.fromkeys(rel + out))
        return merged[:150]

    # -------- integration --------
    def _integrate(self, concept_name: str, structured: Dict[str,str]):
        title = _norm(concept_name).lower()
        cid = self.mem.ensure_concept(title, content=structured.get("definition",""), level=2)
        c = self.mem.get(cid)
        try:
            if self.guidance and hasattr(self.guidance, "focus_facets"):
                _ = list(self.guidance.focus_facets(title) or [])
        except Exception:
            pass
        if structured.get("definition"): c.set_facet("definition", _cap(structured["definition"], 1000))
        if structured.get("examples"):   c.set_facet("example",    _cap(structured["examples"],    900))
        if structured.get("operation"):  c.set_facet("operation",  _cap(structured["operation"],   900))
        if structured.get("cause"):      c.set_facet("cause",      _cap(structured["cause"],       900))
        c.touch()
        self._persist(force=True)

    # -------- subconscious evolution delegation --------
    def _maybe_subconscious_evolve(self, limit: int = 25) -> int:
        if not self.evolve_cb: return 0
        try:
            return int(self.evolve_cb(limit))
        except Exception:
            return 0

    # -------- per-concept --------
    def process_concept(self, concept: str) -> Tuple[bool, str, List[str]]:
        name = _norm(concept)
        if not name:
            return False, "empty_name", []
        page_title, structured = self._fetch_and_structure(name)
        if not page_title:
            # create minimal node to avoid loops
            cid = self.mem.ensure_concept(name.lower(), content="", level=1)
            self.mem.get(cid).touch()
            self._persist(force=True)
            return False, "no_summary", []
        self._integrate(page_title, structured)
        self._maybe_subconscious_evolve(limit=20)
        links = self._related_links(page_title)
        return True, "", links

    # -------- main loop --------
    def autonomous_discovery_loop(
        self,
        max_steps: Optional[int] = None,
        sleep_s: float = 0.0,
        verbose: bool = True,
        status_every: int = 1,
        log_file: str = "harvester_activity.log",
        min_queue_backfill: int = 5
    ):
        steps = 0
        if verbose:
            print("[harvester] starting loop (robust links + sub evolution)", flush=True)

        while True:
            # periodic subconscious evolve pulse
            if (_now() - self._last_sub_evolve) >= self._sub_evolve_every_s:
                if self._maybe_subconscious_evolve(limit=25):
                    self._persist()
                self._last_sub_evolve = _now()

            if max_steps is not None and steps >= max_steps:
                break
            if not self.concept_queue:
                self._persist()
                if verbose:
                    print("[harvester] queue empty", flush=True)
                break

            concept = self.concept_queue.pop(0)
            ok, reason, links = self.process_concept(concept)
            steps += 1

            # rank/filter enqueue
            added = 0; skipped = 0
            starving = (len(self.concept_queue) < min_queue_backfill)
            # We’ll score with guidance if present; in soft mode we'll still keep items when starving
            scored: List[Tuple[float, str]] = []
            for t in links:
                t_norm = _norm(t)
                if not t_norm:
                    skipped += 1
                    continue
                allowed = True
                if self.guidance and hasattr(self.guidance, "allow_candidate"):
                    try:
                        allowed = bool(self.guidance.allow_candidate(t_norm, source=f"wiki:{concept}"))
                    except Exception:
                        allowed = True
                if not allowed and not (self.guidance_soft_mode and starving):
                    skipped += 1
                    continue
                score = 0.5
                if self.guidance and hasattr(self.guidance, "score_candidate"):
                    try:
                        score = float(self.guidance.score_candidate(t_norm, source=f"wiki:{concept}"))
                    except Exception:
                        pass
                scored.append((score, t_norm))

            # insert scored items high→low
            scored.sort(key=lambda x: x[0], reverse=True)
            for _, t in scored:
                if t not in self.discovered_concepts:
                    self.discovered_concepts.add(t)
                    self.concept_queue.append(t)
                    added += 1

            # JSON log (always)
            self._json_log_step(step=steps, concept=concept, ok=ok, log_file=log_file,
                                skip_reason=reason or (f"skipped:{skipped}" if skipped else ""))

            # Console echo (optional)
            if verbose and (steps % max(1, status_every) == 0):
                st = self._stats()
                print(
                    f"[harvester] step={steps} concept='{concept}' ok={ok} added={added} "
                    f"(skipped={skipped}, starving={starving}) | "
                    f"crystals={st['crystals_total']} L1={st['L1']} L2={st['L2']} L3={st['L3']} L4={st['L4']} | "
                    f"def={st['with_definition']} ex={st['with_example']} op={st['with_operation']} cause={st['with_cause']} | "
                    f"edges={st['edges']} queue={st['queue']} discovered={st['discovered']}",
                    flush=True
                )

            if sleep_s > 0:
                time.sleep(sleep_s)

        # final evolve pulse + save
        if self._maybe_subconscious_evolve(limit=30):
            self._persist(force=True)
        else:
            self._persist(force=True)

        if verbose:
            print("[harvester] loop complete", flush=True)

    # compatibility: harvester never evolves itself
    def _evolve_active_concepts(self, *args, **kwargs) -> int:
        return 0
