- **Conversational mode**: synthesizes a short, natural reply (claim → why it matters → next step), not a pile of definitions.
- **Teach-me hook**: you can say _“define X as …”_ or _“X means …”_. It writes that meaning into memory, links it to context, and starts using it immediately.

Paste this at the **very bottom of `chatbot_core_v3.py`** and save.

```python
# ================== TEACH & TALK PATCH ==================
import re
from collections import deque

# ---------- Learning: let the user define terms ----------
_TEACH_PATTERNS = [
    re.compile(r"^\s*define\s+([A-Za-z0-9_\- ]{1,60})\s+as\s+(.+)$", re.I),
    re.compile(r"^\s*([A-Za-z0-9_\- ]{1,60})\s+means\s+(.+)$", re.I),
    re.compile(r"^\s*set\s+meaning\s+of\s+([A-Za-z0-9_\- ]{1,60})\s+to\s+(.+)$", re.I),
]

def _teach_extract(text):
    for pat in _TEACH_PATTERNS:
        m = pat.match(text.strip())
        if m:
            return m.group(1).strip(), m.group(2).strip()
    return None, None

def _ensure(mem, concept, content=None, level=1):
    for cid, c in mem.crystals.items():
        if (c.concept or "").lower() == concept.lower():
            return cid
    return mem.ensure_concept(concept, content or concept, level=level)

def _context_tokens(s):
    return re.findall(r"[A-Za-z0-9_\-]+", s.lower())

def _teach(bot, concept, meaning, context_text):
    mem = bot.mem
    cid = _ensure(mem, concept, meaning, level=1)
    c = mem.get(cid)
    if c:
        # update content and usage
        c.content = meaning
        c.usage_count = (c.usage_count or 0) + 3
    # link to context tokens (strong starting web)
    toks = _context_tokens(context_text)
    neighbors = []
    for tid, tc in mem.crystals.items():
        label = (tc.concept or "").lower()
        if not label: continue
        if label in toks or any(t in label or label in t for t in toks):
            neighbors.append(tid)
    for nid in neighbors[:8]:
        mem.co_access([cid, nid])
        ca, cb = mem.get(cid), mem.get(nid)
        if ca and cb:
            co = min(ca.connections.get(nid,0), cb.connections.get(cid,0))
            mem.synthesize_pair(cid, nid, coaccess_count=co)
    return cid

# ---------- Conversational synthesis (no dictionary dump) ----------
def _tok(s): return re.findall(r"[A-Za-z0-9_\-]+", s.lower())

def _hitlist(mem, toks, k=6):
    scored = []
    for cid, c in mem.crystals.items():
        lab = (c.concept or "").lower()
        if not lab: continue
        if not (lab in toks or any(t in lab or lab in t for t in toks)):
            continue
        use = c.usage_count or 0
        deg = len(c.connections or {})
        lvl = getattr(c, "evolution_level", 1) or 1
        score = use + deg*2 + lvl*3 + 6
        scored.append((score, cid, c))
    scored.sort(key=lambda x: x[0], reverse=True)
    return [cid for _, cid, _ in scored[:k]]

def _shortest_path(mem, a, b, depth=3):
