# ---------------------- chatbot_core_v3.py ----------------------
chatbot_core = r'''
# chatbot_core_v3.py — Facet-aware comprehension + foresight axis
from __future__ import annotations
import re, time, random, math
from typing import List, Optional
from collections import defaultdict
from crystal_engine_v3 import Memory, migrate_facets, facet_slots_for

# ---------------- Teach/Link DSL ----------------
# Supported:
#   define X as Y
#   link A with B
#   teach X.role: text  (e.g., teach pragmatics.definition: how context shapes meaning)
#   your name is Crystal / my name is Sunni
_TEACH_DEF = re.compile(r"^\s*define\s+(.+?)\s+as\s+(.+?)\s*$", re.I)
_LINK_AB   = re.compile(r"^\s*link\s+(.+?)\s+with\s+(.+?)\s*$", re.I)
_TEACH_FAC = re.compile(r"^\s*teach\s+([A-Za-z0-9_\-\.]+)\s*:\s*(.+?)\s*$", re.I)
_SET_NAME  = re.compile(r"^\s*(your|my)\s+name\s+is\s+(.+?)\s*$", re.I)

def _norm(s:str)->str:
    s = re.sub(r"\[Autosave[^\]]*\]"," ", s, flags=re.I)
    s = re.sub(r"\s+"," ", s).strip()
    return s

class FractalCrystalBot:
    def __init__(self, mem: Memory):
        self.mem = mem
        migrate_facets(self.mem)

    # ---------- teaching paths ----------
    def _teach_define(self, x:str, y:str)->str:
        cid = self.mem.ensure_concept(x, content=y, level=1)
        c = self.mem.get(cid)
        c.set_facet("definition", y)
        c.touch(); self.mem.save()
        return f"Learned: {x} = {y}"

    def _teach_link(self, a:str, b:str)->str:
        ca = self.mem.ensure_concept(a, level=1)
        cb = self.mem.ensure_concept(b, level=1)
        self.mem.link(ca, cb, 1)
        self.mem.save()
        return f"Linked {a} ↔ {b}."

    def _teach_facet(self, spec:str, text:str)->str:
        if "." in spec:
            name, role = spec.split(".", 1)
        else:
            return "Use: teach concept.role: text"
        cid = self.mem.ensure_concept(name, level=2)
        c = self.mem.get(cid)
        ok = c.set_facet(role.lower(), text)
        self.mem.save()
        return f"Set {name}.{role}." if ok else f"No such role for this level: {role}"

    def _teach_name(self, whose:str, name:str)->str:
        slot = "bot_name" if whose.lower().startswith("your") else "user_name"
        cid = self.mem.ensure_concept(slot, content=name, level=1)
        self.mem.save()
        return f"Okay — {slot.replace('_',' ')} is {name}."

    def _intents(self, user_input: str) -> Optional[str]:
        s = _norm(user_input)
        m = _TEACH_DEF.match(s)
        if m: return self._teach_define(m.group(1), m.group(2))
        m = _LINK_AB.match(s)
        if m: return self._teach_link(m.group(1), m.group(2))
        m = _TEACH_FAC.match(s)
        if m: return self._teach_facet(m.group(1), m.group(2))
        m = _SET_NAME.match(s)
        if m: return self._teach_name(m.group(1), m.group(2))
        return None

    # ---------- light auto-learn ----------
    def _auto_learn(self, text:str):
        toks = re.findall(r"[A-Za-z0-9_\-]+", text.lower())
        toks = [t for t in toks if len(t) > 2 and t not in ("the","and","for","you","are","with","that","this","from","have")]
        ids = []
        for t in toks[:8]:
            ids.append(self.mem.ensure_concept(t, level=1))
        if ids:
            self.mem.co_access(ids, w=1)

    # ---------- facet helpers ----------
    def _best_match(self, tokens: List[str]) -> Optional[str]:
        tokens = [t.lower() for t in tokens if len(t)>2]
        hits = []
        for cid, c in self.mem.crystals.items():
            name = (c.concept or "").lower()
            if not name: continue
            if any(t in name or name in t for t in tokens):
                hits.append(cid)
        if not hits: return None
        hits.sort(key=lambda id_: len(self.mem.get(id_).connections or {}), reverse=True)
        return hits[0]

    def _get(self, cid: str):
        return self.mem.get(cid)

    def _facet(self, cid: str, role: str) -> Optional[str]:
        c = self._get(cid)
        if not c: return None
        try:
            from crystal_engine_v3 import Crystal  # type hint only
            return c.get_facet(role)
        except Exception:
            return None

    # ---------- foresight (ninth point) ----------
    def _foresight(self, props: List[dict], depth:int=1):
        out = []
        for p in props:
            if p["type"] == "rel":
                out.append(f"{p['sub_name'].capitalize()} may entail adjustments for {p['obj_name']}.")
            elif p["type"] == "infer":
                out.append(f"{p['mid_name'].capitalize()} could bridge towards {p['obj_name']} next.")
        if depth > 1 and out:
            out = out + [f"Projecting further: {o}" for o in out[:1]]
        return out[:2]

    # ---------- comprehension pipeline ----------
    def _propositions(self, focus_ids: List[str]):
        # build relation props and infer triangles
        pairs = []
        for a in focus_ids:
            ca = self._get(a)
            if not ca: continue
            for b,w in sorted((ca.connections or {}).items(), key=lambda kv: kv[1], reverse=True)[:6]:
                if b in focus_ids and a != b:
                    pairs.append((a,b,w))
        # dedupe
        seen = set(); pairs_u = []
        for a,b,w in pairs:
            key = (min(a,b), max(a,b))
            if key in seen: continue
            seen.add(key); pairs_u.append((a,b,w))
        # props
        props = []
        for a,b,w in pairs_u[:8]:
            props.append({
                "type": "rel",
                "sub": a, "obj": b, "w": int(w),
                "sub_name": self._get(a).concept, "obj_name": self._get(b).concept
            })
        # triangle inference
        adj = defaultdict(set)
        for a,b,_ in pairs_u:
            adj[a].add(b); adj[b].add(a)
        for a in adj:
            for b in adj[a]:
                for c in adj[b]:
                    if c in adj[a] and a!=b and b!=c and a!=c:
                        props.append({
                            "type": "infer",
                            "sub": a, "mid": b, "obj": c,
                            "sub_name": self._get(a).concept,
                            "mid_name": self._get(b).concept,
                            "obj_name": self._get(c).concept
                        })
                        if len(props) >= 10: break
                if len(props) >= 10: break
            if len(props) >= 10: break
        return props[:10]

    def _focus(self, text: str) -> List[str]:
        toks = re.findall(r"[A-Za-z0-9_\-]+", text.lower())
        toks = [t for t in toks if len(t)>2]
        hits = []
        for cid, c in self.mem.crystals.items():
            name = (c.concept or "").lower()
            if not name: continue
            if any(t in name or name in t for t in toks):
                hits.append(cid)
        hits.sort(key=lambda id_: len(self.mem.get(id_).connections or {}), reverse=True)
        # add top neighbors
        out, seen = [], set()
        for cid in hits[:6]:
            if cid in seen: continue
            out.append(cid); seen.add(cid)
            conns = self.mem.get(cid).connections or {}
            for nb,_w in sorted(conns.items(), key=lambda kv: kv[1], reverse=True)[:3]:
                if nb not in seen:
                    out.append(nb); seen.add(nb)
        return out[:18]

    # ---------- natural realization using facets ----------
    def _realize(self, text:str, props: List[dict]) -> str:
        # if a clean question, prefer facet roles directly
        m = re.match(r"^\s*what\s+(is|are)\s+(.+?)\??\s*$", text, re.I)
        if m:
            term = m.group(2).strip().lower()
            cid = self._best_match([term])
            if cid:
                d = self._facet(cid, "definition")
                ex = self._facet(cid, "example") or ""
                if d: 
                    return f"{term.capitalize()} means {d}" + (f". Example: {ex}." if ex else ".")
                return f"I use {term}, but need a definition. Say: define {term} as …"
            return f"I don’t know {term} yet. Define {term} as …"

        # otherwise compose 1–2 lines from props + 1 foresight
        lines = []
        for p in props[:2]:
            if p["type"] == "rel":
                lines.append(f"{p['sub_name'].capitalize()} relates to {p['obj_name']}.")
            elif p["type"] == "infer":
                lines.append(f"{p['sub_name'].capitalize()} suggests {p['obj_name']} via {p['mid_name']}.")
        foresight = self._foresight(props, depth=2)
        if foresight:
            lines.append(foresight[0])
        if not lines:
            lines.append("Guide me with a definition (define X as …) or a link (link A with B).")
        return " ".join(lines)

    # ---------- public chat ----------
    def chat(self, user_input: str) -> str:
        s = _norm(user_input)
        taught = self._intents(s)
        if taught:
            return taught
        self._auto_learn(s)
        focus = self._focus(s)
        if not focus:
            return f"I can’t map “{user_input}” yet. Define it for me? (define term as …)"
        props = self._propositions(focus)
        # small reinforcement
        if len(focus) >= 2:
            self.mem.co_access([focus[0], focus[1]], w=1)
            self.mem.maybe_promote(focus[0]); self.mem.maybe_promote(focus[1])
        out = self._realize(s, props)
        try:
            if self.mem.path and self.mem.autosave:
                self.mem.save()
        except Exception:
            pass
        return out
'''

