# crystal_engine_v3.py — Facet/Foresight engine (JSON-backed)
from __future__ import annotations

import json, time, uuid, math, threading, os
from dataclasses import dataclass, field
from typing import Dict, List, Optional

# ====================== Facet Schema ======================
# L1: 3-sided facet, 4 facets total
# L2: 4-sided facet, 6 facets total
# L3: hex polyhedron, 12 canonical facets
# L4: quasi-crystal, 8 outer + 8 inner facets (9th-point = foresight axis lives in chatbot)
FACET_SCHEMA = {
    1: {  # L1
        1: "definition",
        2: "example",
        3: "relation",
        4: "evidence",
    },
    2: {  # L2
        1: "definition",
        2: "example",
        3: "relation",
        4: "abstract",
        5: "context",
        6: "operation",
    },
    3: {  # L3
        1: "cause", 2: "effect",
        3: "condition", 4: "concession",
        5: "analogy", 6: "counterexample",
        7: "generalization", 8: "particular",
        9: "temporal", 10: "spatial",
        11: "agent", 12: "patient",
    },
    4: {  # L4 (outer O* + inner I*)
        1: "O_hypothesis", 2: "O_contradiction",
        3: "O_analogy", 4: "O_abduction",
        5: "O_plan", 6: "O_value",
        7: "O_uncertainty", 8: "O_intent",
        9: "I_def_check", 10: "I_coherence",
        11: "I_causality", 12: "I_evidence",
        13: "I_counterfactual", 14: "I_generalize",
        15: "I_novelty", 16: "I_bridge",
    },
}

def facet_slots_for(level: int) -> dict:
    return FACET_SCHEMA.get(int(level) if level else 1, FACET_SCHEMA[1])

# ====================== Core Structures ======================
@dataclass
class Crystal:
    id: str
    concept: str
    content: str = ""             # legacy definitional text
    connections: Dict[str, int] = field(default_factory=dict)  # neighbor_id -> strength
    usage_count: int = 0
    last_accessed: float = 0.0
    evolution_level: int = 1      # 1..4
    facets: Dict[int, str] = field(default_factory=dict)       # slot_index -> text

    def touch(self):
        self.usage_count += 1
        self.last_accessed = time.time()

    def strengthen(self, other_id: str, w: int = 1):
        self.connections[other_id] = self.connections.get(other_id, 0) + int(w)

    def set_facet(self, role: str, text: str) -> bool:
        roles = facet_slots_for(self.evolution_level)
        slot = next((i for i, r in roles.items() if r == role), None)
        if slot is None:
            return False
        self.facets[slot] = (text or "").strip()
        return True

    def get_facet(self, role: str) -> Optional[str]:
        roles = facet_slots_for(self.evolution_level)
        slot = next((i for i, r in roles.items() if r == role), None)
        if slot is None:
            return None
        return self.facets.get(slot)

@dataclass
class Memory:
    crystals: Dict[str, Crystal] = field(default_factory=dict)
    path: Optional[str] = None
    autosave: bool = True
    _lock: threading.RLock = field(default_factory=threading.RLock, repr=False)

    # -------- CRUD --------
    def get(self, cid: str) -> Optional[Crystal]:
        return self.crystals.get(cid)

    def ensure_concept(self, concept: str, content: Optional[str]=None, level: int=1) -> str:
        concept_l = (concept or "").strip().lower()
        with self._lock:
            for k, c in self.crystals.items():
                if c.concept.strip().lower() == concept_l:
                    if content and not c.get_facet("definition"):
                        c.content = content
                        c.set_facet("definition", content)
                    return k
            cid = str(uuid.uuid4())
            c = Crystal(id=cid, concept=concept_l, content=content or "", evolution_level=int(level or 1))
            if content:
                c.set_facet("definition", content)
            self.crystals[cid] = c
            return cid

    def link(self, a: str, b: str, w: int=1):
        if a == b: return
        with self._lock:
            if a in self.crystals and b in self.crystals:
                self.crystals[a].strengthen(b, w)
                self.crystals[b].strengthen(a, w)

    def co_access(self, cids: List[str], w: int=1):
        with self._lock:
            for cid in cids:
                if cid in self.crystals:
                    self.crystals[cid].touch()
            for i in range(len(cids)):
                for j in range(i+1, len(cids)):
                    self.link(cids[i], cids[j], w)

    # -------- Evolution & Synthesis --------
    def maybe_promote(self, cid: str):
        c = self.crystals.get(cid)
        if not c: return
        deg = len(c.connections)
        if c.evolution_level == 1 and c.usage_count >= 8  and deg >= 3:
            c.evolution_level = 2
        elif c.evolution_level == 2 and c.usage_count >= 20 and deg >= 6:
            c.evolution_level = 3
        elif c.evolution_level == 3 and c.usage_count >= 40 and deg >= 10:
            c.evolution_level = 4

    def synthesize_pair(self, a: str, b: str, coaccess_count: int=1):
        if a not in self.crystals or b not in self.crystals: return None
        ca, cb = self.crystals[a], self.crystals[b]
        self.co_access([a,b], w=coaccess_count)
        self.maybe_promote(a); self.maybe_promote(b)

        # Create a composite node if both >= L2 and the link is strong enough
        w = ca.connections.get(b, 0)
        if ca.evolution_level >= 2 and cb.evolution_level >= 2 and w >= 5:
            label = f"{ca.concept}|{cb.concept}"
            cid = self.ensure_concept(label, content="", level=max(ca.evolution_level, cb.evolution_level))
            self.link(cid, a, 2); self.link(cid, b, 2)
            return cid
        return None

    # -------- Persistence --------
    def save(self, path: Optional[str]=None):
        p = path or self.path
        if not p: return
        data = {
            "crystals": {
                cid: {
                    "id": c.id,
                    "concept": c.concept,
                    "content": c.content,
                    "connections": c.connections,
                    "usage_count": c.usage_count,
                    "last_accessed": c.last_accessed,
                    "evolution_level": c.evolution_level,
                    "facets": c.facets,
                } for cid, c in self.crystals.items()
            }
        }
        tmp = p + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(data, f, ensure_ascii=False)
        # atomic-ish replace
        try:
            if os.path.exists(p):
                os.remove(p)
        except PermissionError:
            # fallback to overwrite
            pass
        os.replace(tmp, p)

    @classmethod
    def load(cls, path: str) -> "Memory":
        try:
            with open(path, "r", encoding="utf-8") as f:
                raw = json.load(f)
        except FileNotFoundError:
            m = cls()
            m.path = path
            return m
        m = cls()
        for cid, d in raw.get("crystals", {}).items():
            c = Crystal(**d)
            m.crystals[cid] = c
        m.path = path
        return m

# ====================== Migration Helpers ======================
DEFAULT_ROLE_MAP = {
    1: [("definition","content"), ("relation", None), ("example", None), ("evidence", None)],
    2: [("definition","content"), ("example", None), ("relation", None), ("abstract", None), ("context", None), ("operation", None)],
    3: [("cause", None), ("effect", None), ("condition", None), ("concession", None),
        ("analogy", None), ("counterexample", None), ("generalization", None), ("particular", None),
        ("temporal", None), ("spatial", None), ("agent", None), ("patient", None)],
    4: [("O_hypothesis", None), ("O_contradiction", None), ("O_analogy", None), ("O_abduction", None),
        ("O_plan", None), ("O_value", None), ("O_uncertainty", None), ("O_intent", None),
        ("I_def_check", None), ("I_coherence", None), ("I_causality", None), ("I_evidence", None),
        ("I_counterfactual", None), ("I_generalize", None), ("I_novelty", None), ("I_bridge", None)],
}

def migrate_facets(mem: Memory):
    """Backfill facet maps and seed definition from content."""
    for cid, c in mem.crystals.items():
        if c.facets is None:
            c.facets = {}
        if c.content and not c.get_facet("definition"):
            c.set_facet("definition", c.content)
        lst = DEFAULT_ROLE_MAP.get(int(c.evolution_level or 1), [])
        roles = facet_slots_for(int(c.evolution_level or 1))
        for role, _src in lst:
            idx = next((i for i, r in roles.items() if r == role), None)
            if idx is not None and idx not in c.facets:
                c.facets[idx] = ""

# ====================== Autopilot (self-compare + pruning) ======================
class Autopilot(threading.Thread):
    def __init__(self, mem: Memory, interval: float=2.5, prune_every:int=50, limit_nodes:int=150000):
        super().__init__(daemon=True)
        self.mem = mem
        self.interval = interval
        self.prune_every = prune_every
        self.limit_nodes = limit_nodes
        self._stop = threading.Event()
        self._ticks = 0

    def stop(self):
        self._stop.set()

    def run(self):
        import random
        while not self._stop.is_set():
            time.sleep(self.interval)
            try:
                ids = list(self.mem.crystals.keys())
                if len(ids) < 2:
                    continue
                a, b = random.sample(ids, 2)
                self.mem.synthesize_pair(a, b, coaccess_count=2)
                self._ticks += 1
                if self._ticks % self.prune_every == 0:
                    self.prune()
                if self.mem.path and self.mem.autosave:
                    self.mem.save()
            except MemoryError:
                self.prune(aggressive=True)

    def prune(self, aggressive: bool=False):
        # prune weakest edges and coldest nodes
        with self.mem._lock:
            for cid, c in list(self.mem.crystals.items()):
                con = c.connections
                for k, w in list(con.items()):
                    if w <= 0 or (aggressive and w < 3):
                        del con[k]
                if aggressive and c.usage_count < 2 and len(con) == 0:
                    del self.mem.crystals[cid]
