    # ====================== Realization (facets → sentences) ======================
    _Q_WHAT = re.compile(r"^\s*what\s+(is|are)\s+(.+?)\??\s*$", re.I)
    _Q_WHY  = re.compile(r"^\s*why\b.*", re.I)
    _Q_HOW  = re.compile(r"^\s*how\b.*", re.I)
    _Q_WHO  = re.compile(r"^\s*who\b.*", re.I)
    _Q_WHEN = re.compile(r"^\s*when\b.*", re.I)
    _Q_WHERE= re.compile(r"^\s*where\b.*", re.I)

    def _realize(self, text:str, props: List[dict]) -> str:
        # WHAT: definitions
        m = self._Q_WHAT.match(text)
        if m:
            term = m.group(2).strip().lower()
            cid = self._best_match([term])
            if cid:
                d = self._facet(cid, "definition")
                ex = self._facet(cid, "example") or ""
                if d:
                    return f"{term.capitalize()} means {d}" + (f". Example: {ex}." if ex else ".")
                return f"I use {term}, but need a definition. Say: define {term} as …"
            return f"I don’t know {term} yet. Define {term} as …"

        # WHY: L3 cause/effect → else evidence
        if self._Q_WHY.match(text):
            cid = self._best_match(re.findall(r"[A-Za-z0-9_\-]+", text.lower()))
            if cid:
                cause = self._facet(cid, "cause")
                effect= self._facet(cid, "effect")
                if cause and effect:
                    return f"Because {cause}, which leads to {effect}."
                ev = self._facet(cid, "evidence")
                if ev:
                    return f"My reason: {ev}"
            return "Tell me what to explain (e.g., “why gravity?”)."

        # HOW: L2 operation
        if self._Q_HOW.match(text):
            cid = self._best_match(re.findall(r"[A-Za-z0-9_\-]+", text.lower()))
            if cid:
                op = self._facet(cid, "operation")
                if op:
                    return f"Here’s how: {op}"
            return "Point me at a target (e.g., “how to tokenize text”)."

        # WHO: L3 Agent/Patient
        if self._Q_WHO.match(text):
            cid = self._best_match(re.findall(r"[A-Za-z0-9_\-]+", text.lower()))
            if cid:
                ag = self._facet(cid, "agent")
                pa = self._facet(cid, "patient")
                if ag and pa:
                    return f"{ag} acts on {pa}."
                if ag:
                    return f"{ag} is the agent involved."
            return "Who with respect to what? Give me the concept."

        # WHEN/WHERE: temporal/spatial
        if self._Q_WHEN.match(text) or self._Q_WHERE.match(text):
            cid = self._best_match(re.findall(r"[A-Za-z0-9_\-]+", text.lower()))
            if cid:
                tm = self._facet(cid, "temporal")
                sp = self._facet(cid, "spatial")
                if tm and sp: return f"It occurs around {tm}, typically in {sp}."
                if tm: return f"It occurs around {tm}."
                if sp: return f"It’s typically in {sp}."
            return "Give me a target so I can fetch time/place facets."

        # Otherwise compose from props + foresight
        lines = []
        for p in props[:2]:
            if p["type"] == "rel":
                lines.append(f"{p['sub_name'].capitalize()} relates to {p['obj_name']}.")
            elif p["type"] == "infer":
                lines.append(f"{p['sub_name'].capitalize()} suggests {p['obj_name']} via {p['mid_name']}.")
        foresight = self._foresight(props, depth=2)
        if foresight:
            lines.append(foresight[0])
        if not lines:
            lines.append("Guide me with a definition (define X as …) or a link (link A with B).")
        return " ".join(lines)

    # ====================== Public chat ======================
    def chat(self, user_input: str) -> str:
        s = _norm(user_input)
        taught = self._intents(s)
        if taught:
            return taught

        self._auto_learn(s)
        focus = self._focus(s)
        if not focus:
            return f"I can’t map “{user_input}” yet. Define it for me? (define term as …)"
        props = self._propositions(focus)

        # small reinforcement for top focus
        if len(focus) >= 2:
            self.mem.co_access([focus[0], focus[1]], w=1)
            self.mem.maybe_promote(focus[0]); self.mem.maybe_promote(focus[1])

        out = self._realize(s, props)

        # autosave
        try:
            if self.mem.path and self.mem.autosave:
                self.mem.save()
        except Exception:
            pass

        return out
