# run_chat_v3_autopilot_autosave.py — Autopilot + Autosave runner
import os, sys, time
from crystal_engine_v3 import Memory, Autopilot, migrate_facets
from chatbot_core_v3 import FractalCrystalBot

# Use env var to point to your memory file, else default local
MEM_PATH = os.environ.get(
    "CRYSTAL_MEM_PATH",
    os.path.join(os.path.dirname(__file__), "memory_fractal.json")
)
AUTOPILOT = os.environ.get("CRYSTAL_AUTOPILOT", "1") != "0"

def main():
    # Load or create memory
    mem = Memory.load(MEM_PATH)
    mem.autosave = True
    migrate_facets(mem)

    bot = FractalCrystalBot(mem)

    ap = None
    if AUTOPILOT:
        ap = Autopilot(mem, interval=2.0, prune_every=60, limit_nodes=150000)
        ap.start()

    print("Crystal AI (Autopilot + Autosave ON). Type 'exit' to quit.")
    try:
        while True:
            try:
                user = input("You: ").strip()
            except EOFError:
                break
            if not user:
                continue
            if user.lower() in ("exit","quit","q"):
                break

            out = bot.chat(user)

            # Autosave line (visible)
            try:
                bot.mem.save(MEM_PATH)
                print(f"[Autosave] {MEM_PATH} (ok)")
            except Exception as e:
                print(f"[Autosave error] {e}")

            print("Bot:", out)
    finally:
        if ap:
            ap.stop()
            time.sleep(0.2)

if __name__ == "__main__":
    main()
